import { GoogleGenAI, Type } from "@google/genai";
import { DrillQuestion } from '../types';

// Initialize Gemini Client
const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

// Helper to get text safely
const getText = (response: any): string => {
    if (response.text) return response.text;
    if (response.candidates && response.candidates[0] && response.candidates[0].content && response.candidates[0].content.parts && response.candidates[0].content.parts[0].text) {
        return response.candidates[0].content.parts[0].text;
    }
    return '';
};

export const generateDrillQuestions = async (root: string, meaning: string): Promise<DrillQuestion[]> => {
  try {
    const prompt = `
      Create 3 multiple-choice questions to test the understanding of the English root word "${root}" which means "${meaning}".
      Focus on derived words.
      The output must be a valid JSON object with a key "questions" containing an array.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            questions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  question: { type: Type.STRING },
                  options: { type: Type.ARRAY, items: { type: Type.STRING } },
                  correctAnswer: { type: Type.STRING },
                  explanation: { type: Type.STRING }
                },
                required: ["question", "options", "correctAnswer", "explanation"]
              }
            }
          }
        }
      }
    });

    const jsonStr = getText(response);
    if (!jsonStr) throw new Error("Empty response from AI");

    const parsed = JSON.parse(jsonStr);
    return parsed.questions || [];

  } catch (error) {
    console.error("Gemini API Error:", error);
    // Fallback static questions if API fails or key is missing
    return [
      {
        question: `Which word contains the root ${root}?`,
        options: ["Example A", "Example B", "Example C", "Example D"],
        correctAnswer: "Example A",
        explanation: "This is a fallback question because the AI service is unavailable."
      }
    ];
  }
};

export const generateDailyChallenge = async (): Promise<{ word: string; definition: string; parts: string[] }> => {
  try {
    const prompt = `
      Select a complex, long English word (C1/C2 level) suitable for morphological analysis (at least 3 parts: prefix, root, suffix).
      Examples: "Incomprehensibility", "Disproportionate".
      Return JSON.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            word: { type: Type.STRING },
            definition: { type: Type.STRING },
            parts: { type: Type.ARRAY, items: { type: Type.STRING } }
          }
        }
      }
    });

    const jsonStr = getText(response);
    if (!jsonStr) throw new Error("Empty response");
    return JSON.parse(jsonStr);

  } catch (error) {
    return {
      word: "Unpredictability",
      definition: "The quality of being unable to be known in advance.",
      parts: ["Un", "predict", "abil", "ity"]
    };
  }
};

import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';

interface WordTreeProps {
  root: string;
  derivatives: string[];
}

interface TreeNode {
  name: string;
  children?: TreeNode[];
}

export const WordTree: React.FC<WordTreeProps> = ({ root, derivatives }) => {
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    if (!svgRef.current) return;

    // Clear previous render
    d3.select(svgRef.current).selectAll("*").remove();

    const width = 600;
    const height = 400;
    const margin = { top: 20, right: 90, bottom: 20, left: 90 };

    const data: TreeNode = {
      name: root,
      children: derivatives.map(d => ({ name: d }))
    };

    const svg = d3.select(svgRef.current)
      .attr("viewBox", `0 0 ${width} ${height}`)
      .append("g")
      .attr("transform", `translate(${margin.left},${margin.top})`);

    const treeLayout = d3.tree<TreeNode>().size([height - margin.top - margin.bottom, width - margin.left - margin.right]);
    const rootNode = d3.hierarchy(data);
    treeLayout(rootNode);

    // Links
    svg.selectAll(".link")
      .data(rootNode.links())
      .enter().append("path")
      .attr("class", "link")
      .attr("fill", "none")
      .attr("stroke", "#57534e") // stone-600
      .attr("stroke-width", 2)
      .attr("d", d3.linkHorizontal()
        .x((d: any) => d.y)
        .y((d: any) => d.x) as any
      );

    // Nodes
    const nodes = svg.selectAll(".node")
      .data(rootNode.descendants())
      .enter().append("g")
      .attr("class", "node")
      .attr("transform", (d: any) => `translate(${d.y},${d.x})`);

    nodes.append("circle")
      .attr("r", 8)
      .attr("fill", (d) => d.depth === 0 ? "#16a34a" : "#ea580c") // Green root, Orange derivatives
      .attr("stroke", "#fff")
      .attr("stroke-width", 2);

    nodes.append("text")
      .attr("dy", ".35em")
      .attr("x", (d) => d.children ? -13 : 13)
      .style("text-anchor", (d) => d.children ? "end" : "start")
      .text((d) => d.data.name)
      .style("font-family", "Merriweather, serif")
      .style("font-size", "14px")
      .style("font-weight", "bold")
      .style("fill", "#292524"); // stone-800

  }, [root, derivatives]);

  return (
    <div className="w-full flex justify-center bg-stone-100 rounded-lg p-4 border border-stone-200 shadow-inner">
      <svg ref={svgRef} className="w-full h-auto max-w-2xl" />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { WordPart, PartType } from '../types';
import { GripVertical, CheckCircle2, RotateCcw } from 'lucide-react';

interface DissectionLabProps {
  parts: WordPart[];
  onComplete: () => void;
}

export const DissectionLab: React.FC<DissectionLabProps> = ({ parts, onComplete }) => {
  // Shuffle parts for the "bank"
  const [bank, setBank] = useState<WordPart[]>([]);
  const [slots, setSlots] = useState<(WordPart | null)[]>([]);
  const [isSuccess, setIsSuccess] = useState(false);

  useEffect(() => {
    // Initialize
    const shuffled = [...parts].sort(() => Math.random() - 0.5);
    setBank(shuffled);
    setSlots(new Array(parts.length).fill(null));
    setIsSuccess(false);
  }, [parts]);

  const handleDragStart = (e: React.DragEvent, item: WordPart, sourceIndex: number, source: 'bank' | 'slot') => {
    e.dataTransfer.setData('application/json', JSON.stringify({ item, sourceIndex, source }));
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
  };

  const handleDropSlot = (e: React.DragEvent, targetIndex: number) => {
    e.preventDefault();
    const data = e.dataTransfer.getData('application/json');
    if (!data) return;

    const { item, sourceIndex, source } = JSON.parse(data);
    const newSlots = [...slots];
    const newBank = [...bank];

    // If there is already something in this slot, swap it back to bank or swap places?
    // Simplified: Only allow drop if slot is empty or replace
    const existingItem = newSlots[targetIndex];

    if (source === 'bank') {
      // Moving from Bank to Slot
      newBank.splice(sourceIndex, 1);
      newSlots[targetIndex] = item;
      if (existingItem) newBank.push(existingItem); // Swap
    } else {
      // Moving from Slot to Slot
      newSlots[sourceIndex] = existingItem;
      newSlots[targetIndex] = item;
    }

    setBank(newBank);
    setSlots(newSlots);
    checkCompletion(newSlots);
  };

  const handleDropBank = (e: React.DragEvent) => {
    e.preventDefault();
    const data = e.dataTransfer.getData('application/json');
    if (!data) return;

    const { item, sourceIndex, source } = JSON.parse(data);

    if (source === 'slot') {
      const newSlots = [...slots];
      const newBank = [...bank];

      newSlots[sourceIndex] = null;
      newBank.push(item);

      setSlots(newSlots);
      setBank(newBank);
    }
  };

  const checkCompletion = (currentSlots: (WordPart | null)[]) => {
    // Reconstruct the intended word from original props order
    const isFull = currentSlots.every(s => s !== null);
    if (!isFull) return;

    // Check if the order matches the original parts
    const isCorrect = currentSlots.every((s, idx) => s && s.text === parts[idx].text);

    if (isCorrect) {
      setIsSuccess(true);
      setTimeout(onComplete, 1500);
    }
  };

  return (
    <div className="flex flex-col items-center gap-8 w-full py-8">
      <div className="text-center">
        <h3 className="text-xl font-bold text-stone-700 mb-2">Dissection Lab</h3>
        <p className="text-stone-500">Drag the parts to reconstruction the meaning.</p>
      </div>

      {/* Target Slots (The Sandwich) */}
      <div className="flex items-center gap-2 p-6 bg-stone-200 rounded-xl shadow-inner min-h-[120px] w-full justify-center">
        {slots.map((slot, index) => (
          <div
            key={`slot-${index}`}
            onDragOver={handleDragOver}
            onDrop={(e) => handleDropSlot(e, index)}
            className={`
              w-32 h-24 rounded-lg border-2 border-dashed flex items-center justify-center transition-all
              ${slot ? 'border-transparent' : 'border-stone-400 bg-stone-100'}
              ${isSuccess ? 'bg-green-100 border-green-500' : ''}
            `}
          >
            {slot ? (
               <div 
                 draggable 
                 onDragStart={(e) => handleDragStart(e, slot, index, 'slot')}
                 className={`
                    w-full h-full rounded-lg shadow-md flex flex-col items-center justify-center cursor-grab active:cursor-grabbing
                    ${slot.type === PartType.ROOT ? 'bg-orange-100 text-orange-900 border border-orange-200' : 'bg-blue-50 text-blue-900 border border-blue-200'}
                 `}
               >
                 <span className="font-bold text-xl">{slot.text}</span>
                 <span className="text-xs opacity-70 uppercase tracking-wider">{slot.meaning}</span>
               </div>
            ) : (
              <span className="text-stone-400 text-sm font-medium">DROP HERE</span>
            )}
          </div>
        ))}
      </div>

      {/* Source Bank */}
      <div 
        onDragOver={handleDragOver}
        onDrop={handleDropBank}
        className="flex flex-wrap justify-center gap-4 p-4 min-h-[100px] w-full border-t border-stone-200"
      >
        {bank.map((item, index) => (
          <div
            key={`bank-${index}-${item.text}`}
            draggable
            onDragStart={(e) => handleDragStart(e, item, index, 'bank')}
            className={`
               px-6 py-4 rounded-lg shadow-sm border-b-4 transform hover:-translate-y-1 transition-all cursor-grab active:cursor-grabbing flex items-center gap-2
               ${item.type === PartType.ROOT ? 'bg-orange-500 border-orange-700 text-white' : 'bg-blue-500 border-blue-700 text-white'}
            `}
          >
            <GripVertical size={16} className="opacity-50" />
            <span className="font-bold text-lg">{item.text}</span>
          </div>
        ))}
      </div>

      {isSuccess && (
        <div className="animate-bounce flex flex-col items-center text-green-600 mt-4">
          <CheckCircle2 size={48} />
          <span className="font-bold text-lg mt-2">Perfect Assembly!</span>
        </div>
      )}

      {!isSuccess && bank.length === 0 && slots.some(s => s === null) === false && (
          <div className="text-red-500 font-medium flex items-center gap-2 cursor-pointer" onClick={() => {
              const shuffled = [...parts].sort(() => Math.random() - 0.5);
              setBank(shuffled);
              setSlots(new Array(parts.length).fill(null));
          }}>
              <RotateCcw size={16} /> Incorrect. Reset?
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Lesson, DrillQuestion } from '../types';
import { generateDrillQuestions } from '../services/geminiService';
import { DissectionLab } from './DissectionLab';
import { WordTree } from './WordTree';
import { ArrowRight, BookOpen, BrainCircuit, Construction, Spade, Trophy } from 'lucide-react';

interface LessonFlowProps {
  lesson: Lesson;
  onComplete: () => void;
  onExit: () => void;
}

type Phase = 'DISCOVERY' | 'DISSECTION' | 'DERIVATION' | 'DRILL';

export const LessonFlow: React.FC<LessonFlowProps> = ({ lesson, onComplete, onExit }) => {
  const [phase, setPhase] = useState<Phase>('DISCOVERY');
  const [drillQuestions, setDrillQuestions] = useState<DrillQuestion[]>([]);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [loadingDrill, setLoadingDrill] = useState(false);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [showAnswer, setShowAnswer] = useState(false);

  // Load drill questions when entering DRILL phase
  useEffect(() => {
    if (phase === 'DRILL' && drillQuestions.length === 0) {
      setLoadingDrill(true);
      generateDrillQuestions(lesson.root, lesson.meaning).then(questions => {
        setDrillQuestions(questions);
        setLoadingDrill(false);
      });
    }
  }, [phase, lesson, drillQuestions.length]);

  // Phase Renderers
  const renderDiscovery = () => (
    <div className="flex flex-col items-center justify-center space-y-8 animate-fade-in p-4">
      <div className="w-64 h-64 bg-stone-200 rounded-full flex items-center justify-center shadow-inner mb-4 relative overflow-hidden group">
         {/* Placeholder for Metaphor Image */}
         <img 
            src={`https://picsum.photos/400/400?random=${lesson.id}`} 
            alt="Metaphor" 
            className="w-full h-full object-cover opacity-80 group-hover:scale-110 transition-transform duration-700" 
         />
         <div className="absolute inset-0 bg-black bg-opacity-30 flex items-center justify-center">
            <span className="text-white text-5xl font-serif font-bold drop-shadow-lg">{lesson.root}</span>
         </div>
      </div>
      <div className="text-center max-w-lg">
        <h2 className="text-3xl font-serif font-bold text-stone-800 mb-4">Meaning: <span className="text-orange-600">{lesson.meaning}</span></h2>
        <p className="text-stone-600 italic text-lg">"{lesson.metaphor}"</p>
      </div>
      <button 
        onClick={() => setPhase('DISSECTION')}
        className="px-8 py-3 bg-stone-800 text-white rounded-full font-bold hover:bg-stone-700 transition flex items-center gap-2"
      >
        Start Dissection <Construction size={20} />
      </button>
    </div>
  );

  const renderDissection = () => (
    <div className="w-full max-w-4xl mx-auto">
      <h2 className="text-2xl font-serif font-bold text-center mb-6">Phase 2: Dissection</h2>
      <div className="bg-white rounded-2xl shadow-xl p-8 border border-stone-200">
        <div className="text-center mb-8">
            <p className="text-stone-500 uppercase tracking-widest text-sm mb-2">Target Word</p>
            <h1 className="text-5xl font-serif font-bold text-stone-900 tracking-wider">
                {lesson.parts.map(p => p.text).join('')}
            </h1>
        </div>
        <DissectionLab 
          parts={lesson.parts} 
          onComplete={() => setPhase('DERIVATION')} 
        />
      </div>
    </div>
  );

  const renderDerivation = () => (
    <div className="w-full max-w-4xl mx-auto flex flex-col items-center">
      <h2 className="text-2xl font-serif font-bold text-center mb-6">Phase 3: Derivation Tree</h2>
      <p className="text-stone-600 mb-6 text-center max-w-lg">See how the root <span className="font-bold text-orange-600">{lesson.root}</span> grows into many different words.</p>

      <div className="w-full bg-white p-4 rounded-2xl shadow-lg border border-stone-200 mb-8">
        <WordTree root={lesson.root} derivatives={lesson.derivatives} />
      </div>

      <button 
        onClick={() => setPhase('DRILL')}
        className="px-8 py-3 bg-stone-800 text-white rounded-full font-bold hover:bg-stone-700 transition flex items-center gap-2"
      >
        Start Drill <BrainCircuit size={20} />
      </button>
    </div>
  );

  const handleOptionSelect = (option: string) => {
    if (showAnswer) return;
    setSelectedOption(option);
    setShowAnswer(true);
    if (option === drillQuestions[currentQuestionIndex].correctAnswer) {
      setScore(s => s + 10);
    }
  };

  const nextQuestion = () => {
    if (currentQuestionIndex < drillQuestions.length - 1) {
      setCurrentQuestionIndex(prev => prev + 1);
      setSelectedOption(null);
      setShowAnswer(false);
    } else {
      onComplete();
    }
  };

  const renderDrill = () => {
    if (loadingDrill) {
      return (
        <div className="flex flex-col items-center justify-center h-64">
           <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-stone-800 mb-4"></div>
           <p className="text-stone-500">AI is crafting your quiz...</p>
        </div>
      );
    }

    const currentQ = drillQuestions[currentQuestionIndex];

    return (
      <div className="w-full max-w-2xl mx-auto">
        <div className="flex justify-between items-center mb-6">
           <h2 className="text-xl font-serif font-bold">Phase 4: Drill</h2>
           <span className="bg-stone-200 px-3 py-1 rounded-full text-sm font-mono">Q{currentQuestionIndex + 1}/{drillQuestions.length}</span>
        </div>

        <div className="bg-white rounded-2xl shadow-xl p-8 border border-stone-200 relative overflow-hidden">
           <h3 className="text-lg font-medium text-stone-800 mb-6 leading-relaxed">{currentQ.question}</h3>

           <div className="space-y-3">
             {currentQ.options.map((option, idx) => {
               let btnClass = "w-full text-left p-4 rounded-xl border-2 transition-all ";
               if (showAnswer) {
                 if (option === currentQ.correctAnswer) btnClass += "bg-green-100 border-green-500 text-green-800";
                 else if (option === selectedOption) btnClass += "bg-red-50 border-red-300 text-red-800";
                 else btnClass += "border-stone-100 text-stone-400";
               } else {
                 btnClass += "border-stone-100 hover:border-stone-300 hover:bg-stone-50";
               }

               return (
                 <button 
                   key={idx}
                   onClick={() => handleOptionSelect(option)}
                   disabled={showAnswer}
                   className={btnClass}
                 >
                   {option}
                 </button>
               );
             })}
           </div>

           {showAnswer && (
             <div className="mt-6 pt-6 border-t border-stone-100 animate-fade-in">
               <p className="text-sm text-stone-600 mb-4"><span className="font-bold">Explanation:</span> {currentQ.explanation}</p>
               <div className="flex justify-end">
                 <button 
                   onClick={nextQuestion}
                   className="px-6 py-2 bg-stone-900 text-white rounded-lg font-bold hover:bg-stone-700"
                 >
                   {currentQuestionIndex === drillQuestions.length - 1 ? 'Finish Lesson' : 'Next Question'}
                 </button>
               </div>
             </div>
           )}
        </div>
      </div>
    );
  };

  // Main Render
  return (
    <div className="min-h-screen bg-stone-50 flex flex-col">
      {/* Header */}
      <div className="bg-white border-b border-stone-200 p-4 flex justify-between items-center sticky top-0 z-10">
        <button onClick={onExit} className="text-stone-500 hover:text-stone-800 text-sm font-bold uppercase tracking-wider">
          &larr; Exit Lesson
        </button>
        <div className="flex gap-2">
           {(['DISCOVERY', 'DISSECTION', 'DERIVATION', 'DRILL'] as Phase[]).map((p, i) => (
             <div key={p} className={`h-2 w-12 rounded-full ${['DISCOVERY', 'DISSECTION', 'DERIVATION', 'DRILL'].indexOf(phase) >= i ? 'bg-orange-500' : 'bg-stone-200'}`} />
           ))}
        </div>
        <div className="font-mono font-bold text-orange-600">XP: {score}</div>
      </div>

      {/* Content Area */}
      <div className="flex-1 p-6 flex items-center justify-center">
        {phase === 'DISCOVERY' && renderDiscovery()}
        {phase === 'DISSECTION' && renderDissection()}
        {phase === 'DERIVATION' && renderDerivation()}
        {phase === 'DRILL' && renderDrill()}
      </div>
    </div>
  );
};

import React from 'react';
import { CURRICULUM } from '../constants';
