interface DashboardProps {
  progress: UserProgress;
  onSelectLesson: (lesson: Lesson) => void;
  onGoToGarden: () => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ progress, onSelectLesson, onGoToGarden }) => {

  const isLessonLocked = (tierId: number, lessonIndex: number) => {
    // Simplified locking logic: Tier 2 locked until 3 Tier 1 lessons are done.
    if (tierId === 1) return false;
    // Count tier 1 completions
    const tier1Ids = CURRICULUM[0].modules.flatMap(m => m.lessons.map(l => l.id));
    const completedT1 = tier1Ids.filter(id => progress.completedLessons.includes(id)).length;
    return completedT1 < 2; // Unlock Tier 2 after 2 foundation lessons
  };

  return (
    <div className="min-h-screen bg-stone-50 p-6 md:p-12">
      <div className="max-w-6xl mx-auto">

        {/* Header */}
        <div className="flex justify-between items-end mb-12">
          <div>
            <h1 className="text-4xl font-serif font-bold text-stone-900 mb-2">Morphology Master</h1>
            <p className="text-stone-500">Master the building blocks of English.</p>
          </div>
          <div 
            onClick={onGoToGarden}
            className="group cursor-pointer bg-green-100 hover:bg-green-200 border border-green-300 px-6 py-3 rounded-xl flex items-center gap-4 transition-all"
          >
            <div className="text-right">
               <p className="text-xs font-bold text-green-800 uppercase tracking-widest">Word Garden</p>
               <p className="text-green-900 font-bold">{progress.garden.trees} Trees Planted</p>
            </div>
            <Leaf className="text-green-600 group-hover:scale-110 transition-transform" size={28} />
          </div>
        </div>

        {/* Curriculum List */}
        <div className="space-y-12">
          {CURRICULUM.map((tier) => (
            <div key={tier.id} className="relative">
              <div className="flex items-center gap-4 mb-6">
                <span className="bg-stone-900 text-stone-50 text-xs font-bold px-3 py-1 rounded-full">TIER {tier.id}</span>
                <h2 className="text-2xl font-serif font-bold text-stone-800">{tier.title.split(":")[1]}</h2>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {tier.modules.map((module) => (
                  <div key={module.id} className="bg-white rounded-xl p-6 shadow-sm border border-stone-200 hover:shadow-md transition-shadow">
                    <h3 className="font-bold text-lg text-stone-800 mb-1">{module.title}</h3>
                    <p className="text-sm text-stone-500 mb-6 h-10">{module.description}</p>

                    <div className="space-y-3">
                      {module.lessons.map((lesson, idx) => {
                        const isCompleted = progress.completedLessons.includes(lesson.id);
                        const isLocked = isLessonLocked(tier.id, idx);

                        return (
                          <button
                            key={lesson.id}
                            disabled={isLocked}
                            onClick={() => onSelectLesson(lesson)}
                            className={`
                              w-full flex items-center justify-between p-3 rounded-lg border text-left transition-all
                              ${isLocked ? 'bg-stone-100 text-stone-400 border-stone-200 cursor-not-allowed' : 'bg-white hover:bg-orange-50 border-stone-200 hover:border-orange-200'}
                            `}
                          >
                            <div className="flex items-center gap-3">
                              {isLocked ? <Lock size={16} /> : isCompleted ? <Star size={16} className="text-yellow-500 fill-current" /> : <Unlock size={16} className="text-orange-500" />}
                              <div>
                                <span className="font-bold block text-sm">{lesson.root}</span>
                                <span className="text-xs opacity-70">{lesson.meaning}</span>
                              </div>
                            </div>
                            {isCompleted && <span className="text-xs font-bold text-green-600">DONE</span>}
                          </button>
                        );
                      })}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

