import React, { useState, useEffect } from 'react';
import { AppView, Lesson, UserProgress } from './types';
import { INITIAL_USER_PROGRESS } from './constants';
import { Dashboard } from './components/Dashboard';
import { LessonFlow } from './components/LessonFlow';
import { WordGarden } from './components/WordGarden';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.DASHBOARD);
  const [activeLesson, setActiveLesson] = useState<Lesson | null>(null);

  // Persist progress to local storage
  const [progress, setProgress] = useState<UserProgress>(() => {
    const saved = localStorage.getItem('morphology_progress');
    return saved ? JSON.parse(saved) : INITIAL_USER_PROGRESS;
  });

  useEffect(() => {
    localStorage.setItem('morphology_progress', JSON.stringify(progress));
  }, [progress]);

  const handleLessonSelect = (lesson: Lesson) => {
    setActiveLesson(lesson);
    setView(AppView.LESSON);
  };

  const handleLessonComplete = () => {
    if (!activeLesson) return;

    // Update progress
    setProgress(prev => {
      const isNew = !prev.completedLessons.includes(activeLesson.id);
      return {
        ...prev,
        xp: prev.xp + 100, // Fixed XP for lesson completion
        completedLessons: isNew ? [...prev.completedLessons, activeLesson.id] : prev.completedLessons,
        garden: {
          ...prev.garden,
          trees: isNew ? prev.garden.trees + 1 : prev.garden.trees
        }
      };
    });

    // Go to Garden to celebrate
    setTimeout(() => {
        setView(AppView.GARDEN);
    }, 500);
  };

  const handleExitLesson = () => {
    setActiveLesson(null);
    setView(AppView.DASHBOARD);
  };

  return (
    <div className="antialiased text-stone-900">
      {view === AppView.DASHBOARD && (
        <Dashboard 
          progress={progress} 
          onSelectLesson={handleLessonSelect} 
          onGoToGarden={() => setView(AppView.GARDEN)} 
        />
      )}

      {view === AppView.LESSON && activeLesson && (
        <LessonFlow 
          lesson={activeLesson} 
          onComplete={handleLessonComplete} 
          onExit={handleExitLesson} 
        />
      )}

      {view === AppView.GARDEN && (
        <WordGarden 
          progress={progress} 
          onBack={() => setView(AppView.DASHBOARD)} 
        />
      )}
    </div>
  );
};

export default App;

