import { GoogleGenAI, Type } from "@google/genai";
import { DrillQuestion, Lesson, PartType } from '../types';

// Initialize Gemini Client
const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

// Helper to get text safely
const getText = (response: any): string => {
    if (response.text) return response.text;
    if (response.candidates && response.candidates[0] && response.candidates[0].content && response.candidates[0].content.parts && response.candidates[0].content.parts[0].text) {
        return response.candidates[0].content.parts[0].text;
    }
    return '';
};

export const generateDrillQuestions = async (root: string, meaning: string): Promise<DrillQuestion[]> => {
  try {
    const prompt = `
      Create 3 multiple-choice questions to test the understanding of the English root/affix "${root}" which means "${meaning}".
      Focus on derived words.
      The output must be a valid JSON object with a key "questions" containing an array.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            questions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  question: { type: Type.STRING },
                  options: { type: Type.ARRAY, items: { type: Type.STRING } },
                  correctAnswer: { type: Type.STRING },
                  explanation: { type: Type.STRING }
                },
                required: ["question", "options", "correctAnswer", "explanation"]
              }
            }
          }
        }
      }
    });

    const jsonStr = getText(response);
    if (!jsonStr) throw new Error("Empty response from AI");

    const parsed = JSON.parse(jsonStr);
    return parsed.questions || [];

  } catch (error) {
    console.error("Gemini API Error:", error);
    return [
      {
        question: `Which word contains the root ${root}?`,
        options: ["Loading Error", "Please Retry", "Check Connection", "Debug"],
        correctAnswer: "Please Retry",
        explanation: "This is a fallback due to an API error."
      }
    ];
  }
};

export const enrichLessonData = async (root: string, category: string): Promise<Partial<Lesson>> => {
  try {
    const prompt = `
      I need educational content for the English morphology lesson on the root/prefix/suffix: "${root}" (Category: ${category}).

      Return a JSON object with:
      1. "meaning": A concise definition of the root/affix.
      2. "metaphor": A visual metaphor description to help remember it.
      3. "parts": Break down a representative word using this root (e.g. if root is 'PORT', break down 'IMPORT').
      4. "derivatives": A list of 5-8 common English words derived from this root.

      Schema:
      {
        meaning: string,
        metaphor: string,
        parts: [{ text: string, type: "PREFIX"|"ROOT"|"SUFFIX", meaning: string }],
        derivatives: string[]
      }
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            meaning: { type: Type.STRING },
            metaphor: { type: Type.STRING },
            derivatives: { type: Type.ARRAY, items: { type: Type.STRING } },
            parts: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  type: { type: Type.STRING, enum: [PartType.PREFIX, PartType.ROOT, PartType.SUFFIX] },
                  meaning: { type: Type.STRING }
                }
              }
            }
          }
        }
      }
    });

    const jsonStr = getText(response);
    if (!jsonStr) throw new Error("Empty response");
    return JSON.parse(jsonStr);

  } catch (error) {
    console.error("Gemini Enrichment Error:", error);
    return {
      meaning: "Meaning unavailable (Offline)",
      metaphor: "A blank canvas.",
      derivatives: [],
      parts: [{ text: root, type: PartType.ROOT, meaning: "Root" }]
    };
  }
};

