import React, { useState, useEffect } from 'react';
import { Lesson, DrillQuestion } from '../types';
import { generateDrillQuestions, enrichLessonData } from '../services/geminiService';
import { DissectionLab } from './DissectionLab';
import { WordTree } from './WordTree';
import { BrainCircuit, Construction, Loader2 } from 'lucide-react';

interface LessonFlowProps {
  lesson: Lesson;
  onComplete: () => void;
  onExit: () => void;
}

type Phase = 'PREPARING' | 'DISCOVERY' | 'DISSECTION' | 'DERIVATION' | 'DRILL';

export const LessonFlow: React.FC<LessonFlowProps> = ({ lesson: initialLesson, onComplete, onExit }) => {
  const [lesson, setLesson] = useState<Lesson>(initialLesson);
  const [phase, setPhase] = useState<Phase>('PREPARING');
  const [drillQuestions, setDrillQuestions] = useState<DrillQuestion[]>([]);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [loadingDrill, setLoadingDrill] = useState(false);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [showAnswer, setShowAnswer] = useState(false);

  // Hydrate lesson data if missing (Hybrid content strategy)
  useEffect(() => {
    const hydrate = async () => {
        if (!lesson.parts || !lesson.derivatives || lesson.derivatives.length === 0) {
            // Need to fetch data
            const enriched = await enrichLessonData(lesson.root, lesson.category);
            setLesson(prev => ({
                ...prev,
                ...enriched
            }));
        }
        setPhase('DISCOVERY');
    };
    hydrate();
  }, [lesson.id]); // Only run on ID change

  // Load drill questions when entering DRILL phase
  useEffect(() => {
    if (phase === 'DRILL' && drillQuestions.length === 0) {
      setLoadingDrill(true);
      // Use the meaning from the potentially enriched lesson
      generateDrillQuestions(lesson.root, lesson.meaning || "Unknown").then(questions => {
        setDrillQuestions(questions);
        setLoadingDrill(false);
      });
    }
  }, [phase, drillQuestions.length, lesson.root, lesson.meaning]);

  if (phase === 'PREPARING') {
      return (
          <div className="flex flex-col items-center justify-center min-h-screen bg-stone-50">
              <Loader2 className="animate-spin text-orange-500 mb-4" size={48} />
              <h2 className="text-xl font-serif font-bold text-stone-700">Analyzing Root: {lesson.root}</h2>
              <p className="text-stone-500">Consulting the etymology archives...</p>
          </div>
      );
  }

  // Phase Renderers
  const renderDiscovery = () => (
    <div className="flex flex-col items-center justify-center space-y-8 animate-fade-in p-4">
      <div className="w-64 h-64 bg-stone-200 rounded-full flex items-center justify-center shadow-inner mb-4 relative overflow-hidden group">
         {/* Placeholder for Metaphor Image */}
         <img 
            src={`https://picsum.photos/400/400?random=${lesson.id}`} 
            alt="Metaphor" 
            className="w-full h-full object-cover opacity-80 group-hover:scale-110 transition-transform duration-700" 
         />
         <div className="absolute inset-0 bg-black bg-opacity-30 flex items-center justify-center">
            <span className="text-white text-5xl font-serif font-bold drop-shadow-lg">{lesson.root}</span>
         </div>
      </div>
      <div className="text-center max-w-lg">
        <h2 className="text-3xl font-serif font-bold text-stone-800 mb-4">Meaning: <span className="text-orange-600">{lesson.meaning}</span></h2>
        <p className="text-stone-600 italic text-lg">"{lesson.metaphor}"</p>
      </div>
      <button 
        onClick={() => setPhase('DISSECTION')}
        className="px-8 py-3 bg-stone-800 text-white rounded-full font-bold hover:bg-stone-700 transition flex items-center gap-2"
      >
        Start Dissection <Construction size={20} />
      </button>
    </div>
  );

  const renderDissection = () => (
    <div className="w-full max-w-4xl mx-auto">
      <h2 className="text-2xl font-serif font-bold text-center mb-6">Phase 2: Dissection</h2>
      <div className="bg-white rounded-2xl shadow-xl p-8 border border-stone-200">
        <div className="text-center mb-8">
            <p className="text-stone-500 uppercase tracking-widest text-sm mb-2">Target Word</p>
            <h1 className="text-5xl font-serif font-bold text-stone-900 tracking-wider">
                {lesson.parts?.map(p => p.text).join('')}
            </h1>
        </div>
        {lesson.parts && (
            <DissectionLab 
            parts={lesson.parts} 
            onComplete={() => setPhase('DERIVATION')} 
            />
        )}
      </div>
    </div>
  );

  const renderDerivation = () => (
    <div className="w-full max-w-4xl mx-auto flex flex-col items-center">
      <h2 className="text-2xl font-serif font-bold text-center mb-6">Phase 3: Derivation Tree</h2>
      <p className="text-stone-600 mb-6 text-center max-w-lg">See how the root <span className="font-bold text-orange-600">{lesson.root}</span> grows into many different words.</p>

      <div className="w-full bg-white p-4 rounded-2xl shadow-lg border border-stone-200 mb-8">
        <WordTree root={lesson.root} derivatives={lesson.derivatives || []} />
      </div>

      <button 
        onClick={() => setPhase('DRILL')}
        className="px-8 py-3 bg-stone-800 text-white rounded-full font-bold hover:bg-stone-700 transition flex items-center gap-2"
      >
        Start Drill <BrainCircuit size={20} />
      </button>
    </div>
  );

  const handleOptionSelect = (option: string) => {
    if (showAnswer) return;
    setSelectedOption(option);
    setShowAnswer(true);
    if (option === drillQuestions[currentQuestionIndex].correctAnswer) {
      setScore(s => s + 10);
    }
  };

  const nextQuestion = () => {
    if (currentQuestionIndex < drillQuestions.length - 1) {
      setCurrentQuestionIndex(prev => prev + 1);
      setSelectedOption(null);
      setShowAnswer(false);
    } else {
      onComplete();
    }
  };

  const renderDrill = () => {
    if (loadingDrill) {
      return (
        <div className="flex flex-col items-center justify-center h-64">
           <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-stone-800 mb-4"></div>
           <p className="text-stone-500">AI is crafting your quiz...</p>
        </div>
      );
    }

    const currentQ = drillQuestions[currentQuestionIndex];

    return (
      <div className="w-full max-w-2xl mx-auto">
        <div className="flex justify-between items-center mb-6">
           <h2 className="text-xl font-serif font-bold">Phase 4: Drill</h2>
           <span className="bg-stone-200 px-3 py-1 rounded-full text-sm font-mono">Q{currentQuestionIndex + 1}/{drillQuestions.length}</span>
        </div>

        <div className="bg-white rounded-2xl shadow-xl p-8 border border-stone-200 relative overflow-hidden">
           <h3 className="text-lg font-medium text-stone-800 mb-6 leading-relaxed">{currentQ.question}</h3>

           <div className="space-y-3">
             {currentQ.options.map((option, idx) => {
               let btnClass = "w-full text-left p-4 rounded-xl border-2 transition-all ";
               if (showAnswer) {
                 if (option === currentQ.correctAnswer) btnClass += "bg-green-100 border-green-500 text-green-800";
                 else if (option === selectedOption) btnClass += "bg-red-50 border-red-300 text-red-800";
                 else btnClass += "border-stone-100 text-stone-400";
               } else {
                 btnClass += "border-stone-100 hover:border-stone-300 hover:bg-stone-50";
               }

               return (
                 <button 
                   key={idx}
                   onClick={() => handleOptionSelect(option)}
                   disabled={showAnswer}
                   className={btnClass}
                 >
                   {option}
                 </button>
               );
             })}
           </div>

           {showAnswer && (
             <div className="mt-6 pt-6 border-t border-stone-100 animate-fade-in">
               <p className="text-sm text-stone-600 mb-4"><span className="font-bold">Explanation:</span> {currentQ.explanation}</p>
               <div className="flex justify-end">
                 <button 
                   onClick={nextQuestion}
                   className="px-6 py-2 bg-stone-900 text-white rounded-lg font-bold hover:bg-stone-700"
                 >
                   {currentQuestionIndex === drillQuestions.length - 1 ? 'Finish Lesson' : 'Next Question'}
                 </button>
               </div>
             </div>
           )}
        </div>
      </div>
    );
  };

  // Main Render
  return (
    <div className="min-h-screen bg-stone-50 flex flex-col">
      {/* Header */}
      <div className="bg-white border-b border-stone-200 p-4 flex justify-between items-center sticky top-0 z-10">
        <button onClick={onExit} className="text-stone-500 hover:text-stone-800 text-sm font-bold uppercase tracking-wider">
          &larr; Exit Lesson
        </button>
        <div className="flex gap-2">
           {(['DISCOVERY', 'DISSECTION', 'DERIVATION', 'DRILL'] as Phase[]).map((p, i) => (
             <div key={p} className={`h-2 w-12 rounded-full ${['DISCOVERY', 'DISSECTION', 'DERIVATION', 'DRILL'].indexOf(phase) >= i ? 'bg-orange-500' : 'bg-stone-200'}`} />
           ))}
        </div>
        <div className="font-mono font-bold text-orange-600">XP: {score}</div>
      </div>

      {/* Content Area */}
      <div className="flex-1 p-6 flex items-center justify-center">
        {phase !== 'PREPARING' && phase === 'DISCOVERY' && renderDiscovery()}
        {phase === 'DISSECTION' && renderDissection()}
        {phase === 'DERIVATION' && renderDerivation()}
        {phase === 'DRILL' && renderDrill()}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { CURRICULUM } from '../constants';
import { Lesson, UserProgress } from '../types';
import { Lock, Unlock, Star, Leaf, ChevronDown, ChevronUp, Book } from 'lucide-react';

interface DashboardProps {
  progress: UserProgress;
  onSelectLesson: (lesson: Lesson) => void;
  onGoToGarden: () => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ progress, onSelectLesson, onGoToGarden }) => {
  const [expandedModules, setExpandedModules] = useState<Record<string, boolean>>({});

  const toggleModule = (moduleId: string) => {
    setExpandedModules(prev => ({
      ...prev,
      [moduleId]: !prev[moduleId]
    }));
  };

  const isLessonLocked = (tierId: number, lessonIndex: number) => {
    // Basic progression logic: Tier 1 open. Tier 2 requires 5 Tier 1 lessons. Tier 3 requires 10 total...
    if (tierId === 1) return false;

    // Total completed
    const totalCompleted = progress.completedLessons.length;
    const required = (tierId - 1) * 5;

    return totalCompleted < required;
  };

  return (
    <div className="min-h-screen bg-stone-50 p-6 md:p-12">
      <div className="max-w-6xl mx-auto">

        {/* Header */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-end mb-12 gap-6">
          <div>
            <h1 className="text-4xl font-serif font-bold text-stone-900 mb-2">Morphology Master</h1>
            <p className="text-stone-500 text-lg">Deconstruct English. Plant your forest.</p>
          </div>
          <div 
            onClick={onGoToGarden}
            className="group cursor-pointer bg-green-100 hover:bg-green-200 border border-green-300 px-6 py-3 rounded-xl flex items-center gap-4 transition-all w-full md:w-auto justify-between md:justify-start"
          >
            <div className="text-right">
               <p className="text-xs font-bold text-green-800 uppercase tracking-widest">Word Garden</p>
               <p className="text-green-900 font-bold">{progress.garden.trees} Trees Planted</p>
            </div>
            <Leaf className="text-green-600 group-hover:scale-110 transition-transform" size={28} />
          </div>
        </div>

        {/* Curriculum List */}
        <div className="space-y-16">
          {CURRICULUM.map((tier) => (
            <div key={tier.id} className="relative">
              <div className="flex items-center gap-4 mb-6 border-b border-stone-200 pb-4">
                <span className="bg-stone-900 text-stone-50 text-xs font-bold px-3 py-1 rounded-full">TIER {tier.id}</span>
                <div>
                   <h2 className="text-2xl font-serif font-bold text-stone-800">{tier.title.split(":")[1]}</h2>
                   <p className="text-stone-500 text-sm">{tier.description}</p>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {tier.modules.map((module) => {
                  const isExpanded = expandedModules[module.id] || false;
                  // Auto-expand first module of Tier 1
                  const shouldExpand = (tier.id === 1 && module.id === "m1_neg") ? true : isExpanded; 

                  return (
                    <div key={module.id} className="bg-white rounded-xl shadow-sm border border-stone-200 overflow-hidden self-start">

                      {/* Module Header */}
                      <div 
                        onClick={() => toggleModule(module.id)}
                        className="p-6 cursor-pointer hover:bg-stone-50 transition-colors flex justify-between items-center"
                      >
                         <div className="flex items-center gap-3">
                             <div className="bg-orange-100 p-2 rounded-lg text-orange-600">
                                 <Book size={20} />
                             </div>
                             <div>
                                <h3 className="font-bold text-lg text-stone-800">{module.title}</h3>
                                <p className="text-xs text-stone-500">{module.lessons.length} Lessons</p>
                             </div>
                         </div>
                         {shouldExpand ? <ChevronUp size={20} className="text-stone-400"/> : <ChevronDown size={20} className="text-stone-400"/>}
                      </div>

                      {/* Lessons List (Collapsible) */}
                      {(shouldExpand || (tier.id === 1 && module.id === "m1_neg")) && (
                        <div className="border-t border-stone-100 bg-stone-50/50 p-2 space-y-1 max-h-[400px] overflow-y-auto custom-scrollbar">
                          {module.lessons.map((lesson, idx) => {
                            const isCompleted = progress.completedLessons.includes(lesson.id);
                            const isLocked = isLessonLocked(tier.id, idx);

                            return (
                              <button
                                key={lesson.id}
                                disabled={isLocked}
                                onClick={() => onSelectLesson(lesson)}
                                className={`
                                  w-full flex items-center justify-between p-3 rounded-lg border text-left transition-all
                                  ${isLocked ? 'opacity-60 bg-transparent border-transparent cursor-not-allowed' : 'bg-white hover:bg-white hover:shadow-md border-transparent hover:border-orange-200'}
                                  ${isCompleted ? 'bg-green-50 border-green-100' : ''}
                                `}
                              >
                                <div className="flex items-center gap-3">
                                  {isLocked ? <Lock size={14} className="text-stone-400" /> : isCompleted ? <Star size={14} className="text-green-500 fill-current" /> : <Unlock size={14} className="text-orange-500" />}
                                  <div>
                                    <span className="font-bold block text-sm text-stone-800">{lesson.root}</span>
                                    <span className="text-xs text-stone-500">{lesson.meaning || "..."}</span>
                                  </div>
                                </div>
                                {isCompleted && <span className="text-[10px] font-bold text-green-600 bg-green-100 px-2 py-0.5 rounded-full">DONE</span>}
                              </button>
                            );
                          })}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Lesson, DrillQuestion } from '../types';
import { generateDrillQuestions, enrichLessonData } from '../services/geminiService';
import { DissectionLab } from './DissectionLab';
import { WordTree } from './WordTree';
import { BrainCircuit, Construction, Loader2, RefreshCw } from 'lucide-react';

interface LessonFlowProps {
  lesson: Lesson;
  onComplete: () => void;
  onExit: () => void;
}

type Phase = 'PREPARING' | 'DISCOVERY' | 'DISSECTION' | 'DERIVATION' | 'DRILL';

export const LessonFlow: React.FC<LessonFlowProps> = ({ lesson: initialLesson, onComplete, onExit }) => {
  const [lesson, setLesson] = useState<Lesson>(initialLesson);
  const [phase, setPhase] = useState<Phase>('PREPARING');
  const [drillQuestions, setDrillQuestions] = useState<DrillQuestion[]>([]);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [loadingDrill, setLoadingDrill] = useState(false);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [showAnswer, setShowAnswer] = useState(false);

  // Hydrate lesson data if missing (Hybrid content strategy)
  useEffect(() => {
    const hydrate = async () => {
        if (!lesson.parts || !lesson.derivatives || lesson.derivatives.length === 0) {
            // Need to fetch data
            const enriched = await enrichLessonData(lesson.root, lesson.category);
            setLesson(prev => ({
                ...prev,
                ...enriched
            }));
        }
        setPhase('DISCOVERY');
    };
    hydrate();
  }, [lesson.id]); // Only run on ID change

  // Load drill questions when entering DRILL phase
  useEffect(() => {
    if (phase === 'DRILL' && drillQuestions.length === 0 && !loadingDrill) {
      setLoadingDrill(true);
      // Use the meaning from the potentially enriched lesson
      generateDrillQuestions(lesson.root, lesson.meaning || "Unknown").then(questions => {
        setDrillQuestions(questions);
        setLoadingDrill(false);
      }).catch(err => {
         console.error(err);
         setLoadingDrill(false);
      });
    }
  }, [phase, drillQuestions.length, lesson.root, lesson.meaning, loadingDrill]);

  if (phase === 'PREPARING') {
      return (
          <div className="flex flex-col items-center justify-center min-h-screen bg-stone-50">
              <Loader2 className="animate-spin text-orange-500 mb-4" size={48} />
              <h2 className="text-xl font-serif font-bold text-stone-700">Analyzing Root: {lesson.root}</h2>
              <p className="text-stone-500">Consulting the etymology archives...</p>
          </div>
      );
  }

  // Phase Renderers
  const renderDiscovery = () => (
    <div className="flex flex-col items-center justify-center space-y-8 animate-fade-in p-4">
      <div className="w-64 h-64 bg-stone-200 rounded-full flex items-center justify-center shadow-inner mb-4 relative overflow-hidden group">
         {/* Placeholder for Metaphor Image */}
         <img 
            src={`https://picsum.photos/400/400?random=${lesson.id}`} 
            alt="Metaphor" 
            className="w-full h-full object-cover opacity-80 group-hover:scale-110 transition-transform duration-700" 
         />
         <div className="absolute inset-0 bg-black bg-opacity-30 flex items-center justify-center">
            <span className="text-white text-5xl font-serif font-bold drop-shadow-lg">{lesson.root}</span>
         </div>
      </div>
      <div className="text-center max-w-lg">
        <h2 className="text-3xl font-serif font-bold text-stone-800 mb-4">Meaning: <span className="text-orange-600">{lesson.meaning}</span></h2>
        <p className="text-stone-600 italic text-lg">"{lesson.metaphor}"</p>
      </div>
      <button 
        onClick={() => setPhase('DISSECTION')}
        className="px-8 py-3 bg-stone-800 text-white rounded-full font-bold hover:bg-stone-700 transition flex items-center gap-2"
      >
        Start Dissection <Construction size={20} />
      </button>
    </div>
  );

  const renderDissection = () => (
    <div className="w-full max-w-4xl mx-auto">
      <h2 className="text-2xl font-serif font-bold text-center mb-6">Phase 2: Dissection</h2>
      <div className="bg-white rounded-2xl shadow-xl p-8 border border-stone-200">
        <div className="text-center mb-8">
            <p className="text-stone-500 uppercase tracking-widest text-sm mb-2">Target Word</p>
            <h1 className="text-5xl font-serif font-bold text-stone-900 tracking-wider">
                {lesson.parts?.map(p => p.text).join('')}
            </h1>
        </div>
        {lesson.parts && (
            <DissectionLab 
            parts={lesson.parts} 
            onComplete={() => setPhase('DERIVATION')} 
            />
        )}
      </div>
    </div>
  );

  const renderDerivation = () => (
    <div className="w-full max-w-4xl mx-auto flex flex-col items-center">
      <h2 className="text-2xl font-serif font-bold text-center mb-6">Phase 3: Derivation Tree</h2>
      <p className="text-stone-600 mb-6 text-center max-w-lg">See how the root <span className="font-bold text-orange-600">{lesson.root}</span> grows into many different words.</p>

      <div className="w-full bg-white p-4 rounded-2xl shadow-lg border border-stone-200 mb-8">
        <WordTree root={lesson.root} derivatives={lesson.derivatives || []} />
      </div>

      <button 
        onClick={() => setPhase('DRILL')}
        className="px-8 py-3 bg-stone-800 text-white rounded-full font-bold hover:bg-stone-700 transition flex items-center gap-2"
      >
        Start Drill <BrainCircuit size={20} />
      </button>
    </div>
  );

  const handleOptionSelect = (option: string) => {
    if (showAnswer) return;
    setSelectedOption(option);
    setShowAnswer(true);
    if (option === drillQuestions[currentQuestionIndex].correctAnswer) {
      setScore(s => s + 10);
    }
  };

  const nextQuestion = () => {
    if (currentQuestionIndex < drillQuestions.length - 1) {
      setCurrentQuestionIndex(prev => prev + 1);
      setSelectedOption(null);
      setShowAnswer(false);
    } else {
      onComplete();
    }
  };

  const renderDrill = () => {
    // Show loading state if loading OR if questions are not yet populated
    if (loadingDrill || !drillQuestions || drillQuestions.length === 0) {
      return (
        <div className="flex flex-col items-center justify-center h-64">
           <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-stone-800 mb-4"></div>
           <p className="text-stone-500">AI is crafting your quiz...</p>
           {!loadingDrill && drillQuestions.length === 0 && (
               <div className="mt-4 text-red-500 flex flex-col items-center">
                   <p>Failed to generate questions.</p>
                   <button 
                     onClick={() => {
                         setLoadingDrill(true);
                         generateDrillQuestions(lesson.root, lesson.meaning || "Unknown").then(questions => {
                            setDrillQuestions(questions);
                            setLoadingDrill(false);
                          });
                     }}
                     className="mt-2 text-stone-800 underline flex items-center gap-1"
                   >
                       <RefreshCw size={14}/> Retry
                   </button>
                   <button 
                     onClick={onComplete}
                     className="mt-4 text-sm text-stone-500"
                   >
                       Skip Drill
                   </button>
               </div>
           )}
        </div>
      );
    }

    const currentQ = drillQuestions[currentQuestionIndex];

    if (!currentQ) {
         return (
             <div className="flex flex-col items-center justify-center h-64 text-red-500">
                 Error loading question {currentQuestionIndex + 1}.
                 <button onClick={onComplete} className="mt-4 underline text-stone-700">Finish Lesson</button>
             </div>
         )
    }

    return (
      <div className="w-full max-w-2xl mx-auto">
        <div className="flex justify-between items-center mb-6">
           <h2 className="text-xl font-serif font-bold">Phase 4: Drill</h2>
           <span className="bg-stone-200 px-3 py-1 rounded-full text-sm font-mono">Q{currentQuestionIndex + 1}/{drillQuestions.length}</span>
        </div>

        <div className="bg-white rounded-2xl shadow-xl p-8 border border-stone-200 relative overflow-hidden">
           <h3 className="text-lg font-medium text-stone-800 mb-6 leading-relaxed">{currentQ.question}</h3>

           <div className="space-y-3">
             {currentQ.options.map((option, idx) => {
               let btnClass = "w-full text-left p-4 rounded-xl border-2 transition-all ";
               if (showAnswer) {
                 if (option === currentQ.correctAnswer) btnClass += "bg-green-100 border-green-500 text-green-800";
                 else if (option === selectedOption) btnClass += "bg-red-50 border-red-300 text-red-800";
                 else btnClass += "border-stone-100 text-stone-400";
               } else {
                 btnClass += "border-stone-100 hover:border-stone-300 hover:bg-stone-50";
               }

               return (
                 <button 
                   key={idx}
                   onClick={() => handleOptionSelect(option)}
                   disabled={showAnswer}
                   className={btnClass}
                 >
                   {option}
                 </button>
               );
             })}
           </div>

           {showAnswer && (
             <div className="mt-6 pt-6 border-t border-stone-100 animate-fade-in">
               <p className="text-sm text-stone-600 mb-4"><span className="font-bold">Explanation:</span> {currentQ.explanation}</p>
               <div className="flex justify-end">
                 <button 
                   onClick={nextQuestion}
                   className="px-6 py-2 bg-stone-900 text-white rounded-lg font-bold hover:bg-stone-700"
                 >
                   {currentQuestionIndex === drillQuestions.length - 1 ? 'Finish Lesson' : 'Next Question'}
                 </button>
               </div>
             </div>
           )}
        </div>
      </div>
    );
  };

  // Main Render
  return (
    <div className="min-h-screen bg-stone-50 flex flex-col">
      {/* Header */}
      <div className="bg-white border-b border-stone-200 p-4 flex justify-between items-center sticky top-0 z-10">
        <button onClick={onExit} className="text-stone-500 hover:text-stone-800 text-sm font-bold uppercase tracking-wider">
          &larr; Exit Lesson
        </button>
        <div className="flex gap-2">
           {(['DISCOVERY', 'DISSECTION', 'DERIVATION', 'DRILL'] as Phase[]).map((p, i) => (
             <div key={p} className={`h-2 w-12 rounded-full ${['DISCOVERY', 'DISSECTION', 'DERIVATION', 'DRILL'].indexOf(phase) >= i ? 'bg-orange-500' : 'bg-stone-200'}`} />
           ))}
        </div>
        <div className="font-mono font-bold text-orange-600">XP: {score}</div>
      </div>

      {/* Content Area */}
      <div className="flex-1 p-6 flex items-center justify-center">
        {phase !== 'PREPARING' && phase === 'DISCOVERY' && renderDiscovery()}
        {phase === 'DISSECTION' && renderDissection()}
        {phase === 'DERIVATION' && renderDerivation()}
        {phase === 'DRILL' && renderDrill()}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Lesson, DrillQuestion } from '../types';
import { generateDrillQuestions, enrichLessonData } from '../services/geminiService';
import { DissectionLab } from './DissectionLab';
import { WordTree } from './WordTree';
import { BrainCircuit, Construction, Loader2, RefreshCw } from 'lucide-react';

interface LessonFlowProps {
  lesson: Lesson;
  onComplete: () => void;
  onExit: () => void;
}

type Phase = 'PREPARING' | 'DISCOVERY' | 'DISSECTION' | 'DERIVATION' | 'DRILL';

export const LessonFlow: React.FC<LessonFlowProps> = ({ lesson: initialLesson, onComplete, onExit }) => {
  const [lesson, setLesson] = useState<Lesson>(initialLesson);
  const [phase, setPhase] = useState<Phase>('PREPARING');
  const [drillQuestions, setDrillQuestions] = useState<DrillQuestion[]>([]);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [loadingDrill, setLoadingDrill] = useState(false);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [showAnswer, setShowAnswer] = useState(false);

  // Hydrate lesson data if missing (Hybrid content strategy)
  useEffect(() => {
    const hydrate = async () => {
        if (!lesson.parts || !lesson.derivatives || lesson.derivatives.length === 0) {
            // Need to fetch data
            const enriched = await enrichLessonData(lesson.root, lesson.category);
            setLesson(prev => ({
                ...prev,
                ...enriched
            }));
        }
        setPhase('DISCOVERY');
    };
    hydrate();
  }, [lesson.id]); // Only run on ID change

  // Load drill questions when entering DRILL phase
  useEffect(() => {
    if (phase === 'DRILL' && drillQuestions.length === 0 && !loadingDrill) {
      setLoadingDrill(true);
      // Use the meaning from the potentially enriched lesson
      generateDrillQuestions(lesson.root, lesson.meaning || "Unknown").then(questions => {
        setDrillQuestions(questions);
        setLoadingDrill(false);
      }).catch(err => {
         console.error(err);
         setLoadingDrill(false);
      });
    }
  }, [phase, drillQuestions.length, lesson.root, lesson.meaning, loadingDrill]);

  if (phase === 'PREPARING') {
      return (
          <div className="flex flex-col items-center justify-center min-h-screen bg-stone-50">
              <Loader2 className="animate-spin text-orange-500 mb-4" size={48} />
              <h2 className="text-xl font-serif font-bold text-stone-700">Analyzing Root: {lesson.root}</h2>
              <p className="text-stone-500">Consulting the etymology archives...</p>
          </div>
      );
  }

  // Phase Renderers
  const renderDiscovery = () => (
    <div className="flex flex-col items-center justify-center space-y-8 animate-fade-in p-4">
      <div className="w-64 h-64 bg-stone-200 rounded-full flex items-center justify-center shadow-inner mb-4 relative overflow-hidden group">
         {/* Placeholder for Metaphor Image */}
         <img 
            src={`https://picsum.photos/400/400?random=${lesson.id}`} 
            alt="Metaphor" 
            className="w-full h-full object-cover opacity-80 group-hover:scale-110 transition-transform duration-700" 
         />
         <div className="absolute inset-0 bg-black bg-opacity-30 flex items-center justify-center">
            <span className="text-white text-5xl font-serif font-bold drop-shadow-lg">{lesson.root}</span>
         </div>
      </div>
      <div className="text-center max-w-lg">
        <h2 className="text-3xl font-serif font-bold text-stone-800 mb-4">Meaning: <span className="text-orange-600">{lesson.meaning}</span></h2>
        <p className="text-stone-600 italic text-lg">"{lesson.metaphor}"</p>
      </div>
      <button 
        onClick={() => setPhase('DISSECTION')}
        className="px-8 py-3 bg-stone-800 text-white rounded-full font-bold hover:bg-stone-700 transition flex items-center gap-2"
      >
        Start Dissection <Construction size={20} />
      </button>
    </div>
  );

  const renderDissection = () => (
    <div className="w-full max-w-4xl mx-auto">
      <h2 className="text-2xl font-serif font-bold text-center mb-6">Phase 2: Dissection</h2>
      <div className="bg-white rounded-2xl shadow-xl p-8 border border-stone-200">
        <div className="text-center mb-8">
            <p className="text-stone-500 uppercase tracking-widest text-sm mb-2">Target Word</p>
            <h1 className="text-5xl font-serif font-bold text-stone-900 tracking-wider">
                {lesson.parts?.map(p => p.text).join('')}
            </h1>
        </div>
        {lesson.parts && (
            <DissectionLab 
            parts={lesson.parts} 
            onComplete={() => setPhase('DERIVATION')} 
            />
        )}
      </div>
    </div>
  );

  const renderDerivation = () => (
    <div className="w-full max-w-4xl mx-auto flex flex-col items-center">
      <h2 className="text-2xl font-serif font-bold text-center mb-6">Phase 3: Derivation Tree</h2>
      <p className="text-stone-600 mb-6 text-center max-w-lg">See how the root <span className="font-bold text-orange-600">{lesson.root}</span> grows into many different words.</p>

      <div className="w-full bg-white p-4 rounded-2xl shadow-lg border border-stone-200 mb-8">
        <WordTree root={lesson.root} derivatives={lesson.derivatives || []} />
      </div>

      <button 
        onClick={() => setPhase('DRILL')}
        className="px-8 py-3 bg-stone-800 text-white rounded-full font-bold hover:bg-stone-700 transition flex items-center gap-2"
      >
        Start Drill <BrainCircuit size={20} />
      </button>
    </div>
  );

  const handleOptionSelect = (option: string) => {
    if (showAnswer) return;
    setSelectedOption(option);
    setShowAnswer(true);
    if (option === drillQuestions[currentQuestionIndex].correctAnswer) {
      setScore(s => s + 10);
    }
  };

  const nextQuestion = () => {
    if (currentQuestionIndex < drillQuestions.length - 1) {
      setCurrentQuestionIndex(prev => prev + 1);
      setSelectedOption(null);
      setShowAnswer(false);
    } else {
      onComplete();
    }
  };

  const renderDrill = () => {
    // Show loading state if loading OR if questions are not yet populated
    if (loadingDrill || !drillQuestions || drillQuestions.length === 0) {
      return (
        <div className="flex flex-col items-center justify-center h-64">
           <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-stone-800 mb-4"></div>
           <p className="text-stone-500">AI is crafting your quiz...</p>
           {!loadingDrill && drillQuestions.length === 0 && (
               <div className="mt-4 text-red-500 flex flex-col items-center">
                   <p>Failed to generate questions.</p>
                   <button 
                     onClick={() => {
                         setLoadingDrill(true);
                         generateDrillQuestions(lesson.root, lesson.meaning || "Unknown").then(questions => {
                            setDrillQuestions(questions);
                            setLoadingDrill(false);
                          });
                     }}
                     className="mt-2 text-stone-800 underline flex items-center gap-1"
                   >
                       <RefreshCw size={14}/> Retry
                   </button>
                   <button 
                     onClick={onComplete}
                     className="mt-4 text-sm text-stone-500"
                   >
                       Skip Drill
                   </button>
               </div>
           )}
        </div>
      );
    }

    const currentQ = drillQuestions[currentQuestionIndex];

    if (!currentQ) {
         return (
             <div className="flex flex-col items-center justify-center h-64 text-red-500">
                 Error loading question {currentQuestionIndex + 1}.
                 <button onClick={onComplete} className="mt-4 underline text-stone-700">Finish Lesson</button>
             </div>
         )
    }

    return (
      <div className="w-full max-w-2xl mx-auto">
        <div className="flex justify-between items-center mb-6">
           <h2 className="text-xl font-serif font-bold">Phase 4: Drill</h2>
           <span className="bg-stone-200 px-3 py-1 rounded-full text-sm font-mono">Q{currentQuestionIndex + 1}/{drillQuestions.length}</span>
        </div>

        <div className="bg-white rounded-2xl shadow-xl p-8 border border-stone-200 relative overflow-hidden">
           <h3 className="text-lg font-medium text-stone-800 mb-6 leading-relaxed">{currentQ.question}</h3>

           <div className="space-y-3">
             {currentQ.options.map((option, idx) => {
               let btnClass = "w-full text-left p-4 rounded-xl border-2 transition-all ";
               if (showAnswer) {
                 if (option === currentQ.correctAnswer) btnClass += "bg-green-100 border-green-500 text-green-800";
                 else if (option === selectedOption) btnClass += "bg-red-50 border-red-300 text-red-800";
                 else btnClass += "border-stone-100 text-stone-400";
               } else {
                 btnClass += "border-stone-100 hover:border-stone-300 hover:bg-stone-50";
               }

               return (
                 <button 
                   key={idx}
                   onClick={() => handleOptionSelect(option)}
                   disabled={showAnswer}
                   className={btnClass}
                 >
                   {option}
                 </button>
               );
             })}
           </div>

           {showAnswer && (
             <div className="mt-6 pt-6 border-t border-stone-100 animate-fade-in">
               <p className="text-sm text-stone-600 mb-4"><span className="font-bold">Explanation:</span> {currentQ.explanation}</p>
               <div className="flex justify-end">
                 <button 
                   onClick={nextQuestion}
                   className="px-6 py-2 bg-stone-900 text-white rounded-lg font-bold hover:bg-stone-700"
                 >
                   {currentQuestionIndex === drillQuestions.length - 1 ? 'Finish Lesson' : 'Next Question'}
                 </button>
               </div>
             </div>
           )}
        </div>
      </div>
    );
  };

  // Main Render
  return (
    <div className="min-h-screen bg-stone-50 flex flex-col">
      {/* Header */}
      <div className="bg-white border-b border-stone-200 p-4 flex justify-between items-center sticky top-0 z-10">
        <button onClick={onExit} className="text-stone-500 hover:text-stone-800 text-sm font-bold uppercase tracking-wider">
          &larr; Exit Lesson
        </button>
        <div className="flex gap-2">
           {(['DISCOVERY', 'DISSECTION', 'DERIVATION', 'DRILL'] as Phase[]).map((p, i) => (
             <div key={p} className={`h-2 w-12 rounded-full ${['DISCOVERY', 'DISSECTION', 'DERIVATION', 'DRILL'].indexOf(phase) >= i ? 'bg-orange-500' : 'bg-stone-200'}`} />
           ))}
        </div>
        <div className="font-mono font-bold text-orange-600">XP: {score}</div>
      </div>

      {/* Content Area */}
      <div className="flex-1 p-6 flex items-center justify-center">
        {phase === 'DISCOVERY' && renderDiscovery()}
        {phase === 'DISSECTION' && renderDissection()}
        {phase === 'DERIVATION' && renderDerivation()}
        {phase === 'DRILL' && renderDrill()}
      </div>
    </div>
  );
};

export enum PartType {
  PREFIX = 'PREFIX',
  ROOT = 'ROOT',
  SUFFIX = 'SUFFIX'
}

export interface WordPart {
  text: string;
  type: PartType;
  meaning: string;
}

export interface Lesson {
  id: string;
  title: string;
  root: string;
  tier: number;
  category: string;
  // Optional fields - populated dynamically by AI if missing
  meaning?: string;
  phonetic?: string; // IPA pronunciation
  parts?: WordPart[]; 
  derivatives?: string[];
  metaphor?: string;
}

export interface Module {
  id: string;
  title: string;
  description: string;
  lessons: Lesson[];
}

export interface Tier {
  id: number;
  title: string;
  description: string;
  modules: Module[];
}

export interface TierAssessmentResult {
  tierId: number;
  score: number; // 0-100
  passed: boolean;
  feedback: string;
  date: string;
}

export interface UserProgress {
  xp: number;
  completedLessons: string[]; // Lesson IDs
  unlockedTiers: number[]; // Explicitly unlocked tiers (via skipping)
  garden: {
    trees: number; // Number of trees planted (1 per lesson)
    level: number;
  };
  assessments: TierAssessmentResult[];
}

export interface User {
  username: string;
  progress: UserProgress;
}

export interface DrillQuestion {
  question: string;
  options: string[];
  correctAnswer: string;
  explanation: string;
}

export enum AppView {
  LOGIN = 'LOGIN',
  DASHBOARD = 'DASHBOARD',
  LESSON = 'LESSON',
  GARDEN = 'GARDEN',
  ASSESSMENT = 'ASSESSMENT'
}

import { User, UserProgress } from '../types';
import { INITIAL_USER_PROGRESS } from '../constants';

const DB_KEY = 'morphology_users_db';
const SESSION_KEY = 'morphology_current_user';

interface UserDatabase {
  [username: string]: UserProgress;
}

// Helper to get DB
const getDB = (): UserDatabase => {
  const db = localStorage.getItem(DB_KEY);
  return db ? JSON.parse(db) : {};
};

// Helper to save DB
const saveDB = (db: UserDatabase) => {
  localStorage.setItem(DB_KEY, JSON.stringify(db));
};

export const loginUser = (username: string): User => {
  const db = getDB();
  let progress = db[username];

  if (!progress) {
    // New user, create entry
    progress = { ...INITIAL_USER_PROGRESS };
    db[username] = progress;
    saveDB(db);
  }

  const user = { username, progress };
  localStorage.setItem(SESSION_KEY, JSON.stringify(user));
  return user;
};

export const logoutUser = () => {
  localStorage.removeItem(SESSION_KEY);
};

export const getCurrentUser = (): User | null => {
  const session = localStorage.getItem(SESSION_KEY);
  return session ? JSON.parse(session) : null;
};

export const saveUserProgress = (username: string, progress: UserProgress) => {
  const db = getDB();
  db[username] = progress;
  saveDB(db);

  // Also update session
  localStorage.setItem(SESSION_KEY, JSON.stringify({ username, progress }));
};

