import React, { useState, useEffect } from 'react';
import { DrillQuestion, TierAssessmentResult } from '../types';
import { generateTierAssessment, evaluateAssessment } from '../services/geminiService';
import { CheckCircle, XCircle, Loader2, Award, AlertCircle } from 'lucide-react';

interface TierAssessmentProps {
  tierId: number;
  roots: string[];
  onComplete: (result: TierAssessmentResult) => void;
  onCancel: () => void;
}

export const TierAssessment: React.FC<TierAssessmentProps> = ({ tierId, roots, onComplete, onCancel }) => {
  const [loading, setLoading] = useState(true);
  const [questions, setQuestions] = useState<DrillQuestion[]>([]);
  const [answers, setAnswers] = useState<Record<number, string>>({});
  const [finished, setFinished] = useState(false);
  const [evaluation, setEvaluation] = useState('');
  const [evaluating, setEvaluating] = useState(false);

  useEffect(() => {
    generateTierAssessment(tierId, roots).then(qs => {
        setQuestions(qs);
        setLoading(false);
    });
  }, [tierId]);

  const handleSelect = (idx: number, opt: string) => {
    setAnswers(prev => ({ ...prev, [idx]: opt }));
  };

  const submitExam = async () => {
    setFinished(true);
    setEvaluating(true);

    let score = 0;
    const missedConcepts: string[] = [];

    questions.forEach((q, idx) => {
        if (answers[idx] === q.correctAnswer) {
            score++;
        } else {
            missedConcepts.push(q.question.substring(0, 20) + "..."); // Rough tracking
        }
    });

    const finalScore = Math.round((score / questions.length) * 100);
    const passed = finalScore >= 70;

    const feedback = await evaluateAssessment(tierId, score, questions.length, missedConcepts);
    setEvaluation(feedback);
    setEvaluating(false);

    // Auto-save after delay
    setTimeout(() => {
        onComplete({
            tierId,
            score: finalScore,
            passed,
            feedback,
            date: new Date().toISOString()
        });
    }, 4000);
  };

  if (loading) {
      return (
          <div className="flex flex-col items-center justify-center min-h-[60vh]">
              <Loader2 className="animate-spin text-orange-500 mb-4" size={48} />
              <h2 className="text-xl font-bold text-stone-700">Generating Tier {tierId} Exam...</h2>
              <p className="text-stone-500">Consulting the AI for challenging questions.</p>
          </div>
      );
  }

  if (finished) {
      const score = Object.keys(answers).filter(k => answers[parseInt(k)] === questions[parseInt(k)].correctAnswer).length;
      const passed = (score / questions.length) >= 0.7;

      return (
          <div className="max-w-2xl mx-auto bg-white p-8 rounded-2xl shadow-xl text-center">
              {passed ? (
                  <div className="flex flex-col items-center text-green-600 mb-6">
                      <Award size={64} className="mb-2" />
                      <h2 className="text-3xl font-serif font-bold">Tier Mastered!</h2>
                  </div>
              ) : (
                  <div className="flex flex-col items-center text-orange-600 mb-6">
                      <AlertCircle size={64} className="mb-2" />
                      <h2 className="text-3xl font-serif font-bold">Keep Practicing</h2>
                  </div>
              )}

              <p className="text-4xl font-bold text-stone-800 mb-6">{score} / {questions.length}</p>

              <div className="bg-stone-50 p-6 rounded-xl border border-stone-200 mb-6">
                 <h3 className="font-bold text-stone-700 mb-2">AI Assessment:</h3>
                 {evaluating ? <Loader2 className="animate-spin mx-auto text-stone-400" /> : <p className="text-stone-600 italic">"{evaluation}"</p>}
              </div>

              <p className="text-stone-400 text-sm">Saving results and returning...</p>
          </div>
      );
  }

  return (
    <div className="max-w-3xl mx-auto pb-12">
        <div className="flex justify-between items-center mb-8">
            <h1 className="text-2xl font-serif font-bold">Tier {tierId} Assessment</h1>
            <button onClick={onCancel} className="text-stone-500 underline">Cancel</button>
        </div>

        <div className="space-y-8">
            {questions.map((q, idx) => (
                <div key={idx} className="bg-white p-6 rounded-xl shadow-sm border border-stone-200">
                    <div className="flex gap-4 mb-4">
                        <span className="bg-stone-900 text-white w-8 h-8 rounded-full flex items-center justify-center font-bold flex-shrink-0">{idx + 1}</span>
                        <h3 className="text-lg font-medium">{q.question}</h3>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-3 pl-12">
                        {q.options.map(opt => (
                            <button
                                key={opt}
                                onClick={() => handleSelect(idx, opt)}
                                className={`p-3 rounded-lg border-2 text-left transition-all ${answers[idx] === opt ? 'border-orange-500 bg-orange-50 text-orange-900' : 'border-stone-100 hover:bg-stone-50'}`}
                            >
                                {opt}
                            </button>
                        ))}
                    </div>
                </div>
            ))}
        </div>

        <div className="mt-8 flex justify-end">
            <button 
                onClick={submitExam}
                disabled={Object.keys(answers).length < questions.length}
                className={`px-8 py-4 rounded-full font-bold text-lg shadow-lg transition-all ${Object.keys(answers).length < questions.length ? 'bg-stone-300 cursor-not-allowed' : 'bg-stone-900 text-white hover:bg-stone-700'}`}
            >
                Submit Exam
            </button>
        </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Lesson, DrillQuestion } from '../types';
import { generateDrillQuestions, enrichLessonData } from '../services/geminiService';
import { DissectionLab } from './DissectionLab';
import { WordTree } from './WordTree';
import { BrainCircuit, Construction, Loader2, RefreshCw, Volume2 } from 'lucide-react';

interface LessonFlowProps {
  lesson: Lesson;
  onComplete: () => void;
  onExit: () => void;
}

type Phase = 'PREPARING' | 'DISCOVERY' | 'DISSECTION' | 'DERIVATION' | 'DRILL';

export const LessonFlow: React.FC<LessonFlowProps> = ({ lesson: initialLesson, onComplete, onExit }) => {
  const [lesson, setLesson] = useState<Lesson>(initialLesson);
  const [phase, setPhase] = useState<Phase>('PREPARING');
  const [drillQuestions, setDrillQuestions] = useState<DrillQuestion[]>([]);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [loadingDrill, setLoadingDrill] = useState(false);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [showAnswer, setShowAnswer] = useState(false);

  // Hydrate lesson data if missing (Hybrid content strategy)
  useEffect(() => {
    const hydrate = async () => {
        // Enriched if missing pronunciation or parts
        if (!lesson.phonetic || !lesson.parts || !lesson.derivatives || lesson.derivatives.length === 0) {
            const enriched = await enrichLessonData(lesson.root, lesson.category);
            setLesson(prev => ({
                ...prev,
                ...enriched
            }));
        }
        setPhase('DISCOVERY');
    };
    hydrate();
  }, [lesson.id]);

  // Load drill questions when entering DRILL phase
  useEffect(() => {
    if (phase === 'DRILL' && drillQuestions.length === 0 && !loadingDrill) {
      setLoadingDrill(true);
      generateDrillQuestions(lesson.root, lesson.meaning || "Unknown").then(questions => {
        setDrillQuestions(questions);
        setLoadingDrill(false);
      }).catch(err => {
         console.error(err);
         setLoadingDrill(false);
      });
    }
  }, [phase, drillQuestions.length, lesson.root, lesson.meaning, loadingDrill]);

  const playAudio = (text: string) => {
    if ('speechSynthesis' in window) {
        const utterance = new SpeechSynthesisUtterance(text);
        utterance.lang = 'en-US';
        utterance.rate = 0.8; // Slightly slower for learning
        window.speechSynthesis.speak(utterance);
    }
  };

  if (phase === 'PREPARING') {
      return (
          <div className="flex flex-col items-center justify-center min-h-screen bg-stone-50">
              <Loader2 className="animate-spin text-orange-500 mb-4" size={48} />
              <h2 className="text-xl font-serif font-bold text-stone-700">Analyzing Root: {lesson.root}</h2>
              <p className="text-stone-500">Consulting the etymology archives...</p>
          </div>
      );
  }

  // Phase Renderers
  const renderDiscovery = () => (
    <div className="flex flex-col items-center justify-center space-y-8 animate-fade-in p-4">
      <div className="w-64 h-64 bg-stone-200 rounded-full flex items-center justify-center shadow-inner mb-4 relative overflow-hidden group">
         <img 
            src={`https://picsum.photos/400/400?random=${lesson.id}`} 
            alt="Metaphor" 
            className="w-full h-full object-cover opacity-80 group-hover:scale-110 transition-transform duration-700" 
         />
         <div className="absolute inset-0 bg-black bg-opacity-30 flex items-center justify-center">
            <span className="text-white text-5xl font-serif font-bold drop-shadow-lg">{lesson.root}</span>
         </div>
      </div>
      <div className="text-center max-w-lg">
        <h2 className="text-3xl font-serif font-bold text-stone-800 mb-2">
            Meaning: <span className="text-orange-600">{lesson.meaning}</span>
        </h2>

        {/* Pronunciation Section */}
        <div className="flex items-center justify-center gap-3 mb-4 bg-white/50 py-2 px-4 rounded-full inline-flex">
            <span className="font-mono text-stone-600 text-lg">{lesson.phonetic || `/${lesson.root.toLowerCase()}/`}</span>
            <button 
                onClick={() => playAudio(lesson.root)}
                className="p-2 rounded-full bg-stone-200 hover:bg-orange-200 hover:text-orange-700 transition-colors"
                title="Listen"
            >
                <Volume2 size={20} />
            </button>
        </div>

        <p className="text-stone-600 italic text-lg">"{lesson.metaphor}"</p>
      </div>
      <button 
        onClick={() => setPhase('DISSECTION')}
        className="px-8 py-3 bg-stone-800 text-white rounded-full font-bold hover:bg-stone-700 transition flex items-center gap-2"
      >
        Start Dissection <Construction size={20} />
      </button>
    </div>
  );

  const renderDissection = () => (
    <div className="w-full max-w-4xl mx-auto">
      <h2 className="text-2xl font-serif font-bold text-center mb-6">Phase 2: Dissection</h2>
      <div className="bg-white rounded-2xl shadow-xl p-8 border border-stone-200">
        <div className="text-center mb-8">
            <p className="text-stone-500 uppercase tracking-widest text-sm mb-2">Target Word</p>
            <div className="flex items-center justify-center gap-4">
                <h1 className="text-5xl font-serif font-bold text-stone-900 tracking-wider">
                    {lesson.parts?.map(p => p.text).join('')}
                </h1>
                <button 
                    onClick={() => playAudio(lesson.parts?.map(p => p.text).join('') || '')}
                    className="p-3 rounded-full bg-stone-100 hover:bg-orange-100 text-stone-600 hover:text-orange-600 transition-colors"
                >
                    <Volume2 size={24} />
                </button>
            </div>
        </div>
        {lesson.parts && (
            <DissectionLab 
            parts={lesson.parts} 
            onComplete={() => setPhase('DERIVATION')} 
            />
        )}
      </div>
    </div>
  );

  const renderDerivation = () => (
    <div className="w-full max-w-4xl mx-auto flex flex-col items-center">
      <h2 className="text-2xl font-serif font-bold text-center mb-6">Phase 3: Derivation Tree</h2>
      <p className="text-stone-600 mb-6 text-center max-w-lg">See how the root <span className="font-bold text-orange-600">{lesson.root}</span> grows into many different words.</p>

      <div className="w-full bg-white p-4 rounded-2xl shadow-lg border border-stone-200 mb-8">
        <WordTree root={lesson.root} derivatives={lesson.derivatives || []} />
      </div>

      <button 
        onClick={() => setPhase('DRILL')}
        className="px-8 py-3 bg-stone-800 text-white rounded-full font-bold hover:bg-stone-700 transition flex items-center gap-2"
      >
        Start Drill <BrainCircuit size={20} />
      </button>
    </div>
  );

  const handleOptionSelect = (option: string) => {
    if (showAnswer) return;
    setSelectedOption(option);
    setShowAnswer(true);
    if (option === drillQuestions[currentQuestionIndex].correctAnswer) {
      setScore(s => s + 10);
    }
  };

  const nextQuestion = () => {
    if (currentQuestionIndex < drillQuestions.length - 1) {
      setCurrentQuestionIndex(prev => prev + 1);
      setSelectedOption(null);
      setShowAnswer(false);
    } else {
      onComplete();
    }
  };

  const renderDrill = () => {
    if (loadingDrill || !drillQuestions || drillQuestions.length === 0) {
      return (
        <div className="flex flex-col items-center justify-center h-64">
           <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-stone-800 mb-4"></div>
           <p className="text-stone-500">AI is crafting your quiz...</p>
           {!loadingDrill && drillQuestions.length === 0 && (
               <div className="mt-4 text-red-500 flex flex-col items-center">
                   <p>Failed to generate questions.</p>
                   <button 
                     onClick={() => {
                         setLoadingDrill(true);
                         generateDrillQuestions(lesson.root, lesson.meaning || "Unknown").then(questions => {
                            setDrillQuestions(questions);
                            setLoadingDrill(false);
                          });
                     }}
                     className="mt-2 text-stone-800 underline flex items-center gap-1"
                   >
                       <RefreshCw size={14}/> Retry
                   </button>
                   <button onClick={onComplete} className="mt-4 text-sm text-stone-500">Skip Drill</button>
               </div>
           )}
        </div>
      );
    }

    const currentQ = drillQuestions[currentQuestionIndex];

    if (!currentQ) return null;

    return (
      <div className="w-full max-w-2xl mx-auto">
        <div className="flex justify-between items-center mb-6">
           <h2 className="text-xl font-serif font-bold">Phase 4: Drill</h2>
           <span className="bg-stone-200 px-3 py-1 rounded-full text-sm font-mono">Q{currentQuestionIndex + 1}/{drillQuestions.length}</span>
        </div>

        <div className="bg-white rounded-2xl shadow-xl p-8 border border-stone-200 relative overflow-hidden">
           <h3 className="text-lg font-medium text-stone-800 mb-6 leading-relaxed">{currentQ.question}</h3>

           <div className="space-y-3">
             {currentQ.options.map((option, idx) => {
               let btnClass = "w-full text-left p-4 rounded-xl border-2 transition-all ";
               if (showAnswer) {
                 if (option === currentQ.correctAnswer) btnClass += "bg-green-100 border-green-500 text-green-800";
                 else if (option === selectedOption) btnClass += "bg-red-50 border-red-300 text-red-800";
                 else btnClass += "border-stone-100 text-stone-400";
               } else {
                 btnClass += "border-stone-100 hover:border-stone-300 hover:bg-stone-50";
               }

               return (
                 <button 
                   key={idx}
                   onClick={() => handleOptionSelect(option)}
                   disabled={showAnswer}
                   className={btnClass}
                 >
                   {option}
                 </button>
               );
             })}
           </div>

           {showAnswer && (
             <div className="mt-6 pt-6 border-t border-stone-100 animate-fade-in">
               <p className="text-sm text-stone-600 mb-4"><span className="font-bold">Explanation:</span> {currentQ.explanation}</p>
               <div className="flex justify-end">
                 <button 
                   onClick={nextQuestion}
                   className="px-6 py-2 bg-stone-900 text-white rounded-lg font-bold hover:bg-stone-700"
                 >
                   {currentQuestionIndex === drillQuestions.length - 1 ? 'Finish Lesson' : 'Next Question'}
                 </button>
               </div>
             </div>
           )}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-stone-50 flex flex-col">
      <div className="bg-white border-b border-stone-200 p-4 flex justify-between items-center sticky top-0 z-10">
        <button onClick={onExit} className="text-stone-500 hover:text-stone-800 text-sm font-bold uppercase tracking-wider">
          &larr; Exit Lesson
        </button>
        <div className="flex gap-2">
           {(['DISCOVERY', 'DISSECTION', 'DERIVATION', 'DRILL'] as Phase[]).map((p, i) => (
             <div key={p} className={`h-2 w-12 rounded-full ${['DISCOVERY', 'DISSECTION', 'DERIVATION', 'DRILL'].indexOf(phase) >= i ? 'bg-orange-500' : 'bg-stone-200'}`} />
           ))}
        </div>
        <div className="font-mono font-bold text-orange-600">XP: {score}</div>
      </div>
      <div className="flex-1 p-6 flex items-center justify-center">
        {phase === 'DISCOVERY' && renderDiscovery()}
        {phase === 'DISSECTION' && renderDissection()}
        {phase === 'DERIVATION' && renderDerivation()}
        {phase === 'DRILL' && renderDrill()}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { CURRICULUM } from '../constants';
import { Lesson, UserProgress } from '../types';
import { Lock, Unlock, Star, Leaf, ChevronDown, ChevronUp, Book, LogOut, GraduationCap, CheckCircle } from 'lucide-react';

interface DashboardProps {
  user: { username: string };
  progress: UserProgress;
  onSelectLesson: (lesson: Lesson) => void;
  onGoToGarden: () => void;
  onTakeAssessment: (tierId: number, roots: string[]) => void;
  onLogout: () => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ user, progress, onSelectLesson, onGoToGarden, onTakeAssessment, onLogout }) => {
  const [expandedModules, setExpandedModules] = useState<Record<string, boolean>>({});

  const toggleModule = (moduleId: string) => {
    setExpandedModules(prev => ({
      ...prev,
      [moduleId]: !prev[moduleId]
    }));
  };

  const isTierUnlocked = (tierId: number) => {
      // Always unlock Tier 1
      if (tierId === 1) return true;
      // Unlock if in unlockedTiers list (from skipping)
      if (progress.unlockedTiers.includes(tierId)) return true;

      // Unlock if previous tier assessment passed
      const prevTierAssessment = progress.assessments.find(a => a.tierId === tierId - 1 && a.passed);
      if (prevTierAssessment) return true;

      // Legacy logic fallback: Check if enough lessons from previous tier are done
      // (Simplified for this version to rely on Assessments mainly for unlocking)
      return false; 
  };

  return (
    <div className="min-h-screen bg-stone-50 p-6 md:p-12">
      <div className="max-w-6xl mx-auto">

        {/* Header */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-end mb-12 gap-6">
          <div>
            <div className="flex items-center gap-3 mb-2">
                <h1 className="text-4xl font-serif font-bold text-stone-900">Morphology Master</h1>
                <span className="text-stone-400 text-sm font-mono px-2 py-1 bg-stone-100 rounded">v2.0</span>
            </div>
            <p className="text-stone-500 text-lg">Welcome back, <span className="font-bold text-stone-800">{user.username}</span>.</p>
          </div>

          <div className="flex gap-4 w-full md:w-auto">
             <div 
                onClick={onGoToGarden}
                className="cursor-pointer bg-green-100 hover:bg-green-200 border border-green-300 px-6 py-3 rounded-xl flex items-center gap-4 transition-all flex-1 md:flex-none"
            >
                <div className="text-right">
                <p className="text-xs font-bold text-green-800 uppercase tracking-widest">Garden</p>
                <p className="text-green-900 font-bold">{progress.garden.trees} Plants</p>
                </div>
                <Leaf className="text-green-600" size={28} />
            </div>

            <button 
                onClick={onLogout}
                className="bg-stone-200 hover:bg-stone-300 p-3 rounded-xl transition-colors"
                title="Logout"
            >
                <LogOut size={24} className="text-stone-600" />
            </button>
          </div>
        </div>

        {/* Curriculum List */}
        <div className="space-y-16">
          {CURRICULUM.map((tier) => {
            const unlocked = isTierUnlocked(tier.id);
            const passedAssessment = progress.assessments.find(a => a.tierId === tier.id && a.passed);
            // Gather all roots for this tier for assessment generation
            const tierRoots = tier.modules.flatMap(m => m.lessons.map(l => l.root));

            return (
                <div key={tier.id} className={`relative ${!unlocked ? 'opacity-60 grayscale' : ''}`}>
                <div className="flex items-center justify-between mb-6 border-b border-stone-200 pb-4">
                    <div className="flex items-center gap-4">
                        <span className={`text-stone-50 text-xs font-bold px-3 py-1 rounded-full ${unlocked ? 'bg-stone-900' : 'bg-stone-400'}`}>TIER {tier.id}</span>
                        <div>
                            <h2 className="text-2xl font-serif font-bold text-stone-800">{tier.title.split(":")[1]}</h2>
                            <p className="text-stone-500 text-sm">{tier.description}</p>
                        </div>
                    </div>

                    {/* Tier Assessment / Skip Button */}
                    <div>
                        {passedAssessment ? (
                            <div className="flex items-center gap-2 text-green-600 font-bold bg-green-50 px-4 py-2 rounded-lg">
                                <CheckCircle size={20} /> Tier Mastered
                            </div>
                        ) : (
                            <button 
                                onClick={() => onTakeAssessment(tier.id, tierRoots)}
                                className="flex items-center gap-2 bg-orange-100 hover:bg-orange-200 text-orange-800 px-4 py-2 rounded-lg font-bold transition-colors text-sm"
                            >
                                <GraduationCap size={18} />
                                {unlocked ? "Take Final Exam" : "Skip to this Tier"}
                            </button>
                        )}
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {tier.modules.map((module) => {
                    const isExpanded = expandedModules[module.id] || false;
                    const shouldExpand = (tier.id === 1 && module.id === "m1_neg") ? true : isExpanded; 

                    return (
                        <div key={module.id} className="bg-white rounded-xl shadow-sm border border-stone-200 overflow-hidden self-start">
                        <div 
                            onClick={() => unlocked && toggleModule(module.id)}
                            className={`p-6 cursor-pointer transition-colors flex justify-between items-center ${unlocked ? 'hover:bg-stone-50' : 'cursor-not-allowed'}`}
                        >
                            <div className="flex items-center gap-3">
                                <div className="bg-orange-100 p-2 rounded-lg text-orange-600">
                                    <Book size={20} />
                                </div>
                                <div>
                                    <h3 className="font-bold text-lg text-stone-800">{module.title}</h3>
                                    <p className="text-xs text-stone-500">{module.lessons.length} Lessons</p>
                                </div>
                            </div>
                            {shouldExpand ? <ChevronUp size={20} className="text-stone-400"/> : <ChevronDown size={20} className="text-stone-400"/>}
                        </div>

                        {(shouldExpand || (tier.id === 1 && module.id === "m1_neg")) && unlocked && (
                            <div className="border-t border-stone-100 bg-stone-50/50 p-2 space-y-1 max-h-[400px] overflow-y-auto custom-scrollbar">
                            {module.lessons.map((lesson) => {
                                const isCompleted = progress.completedLessons.includes(lesson.id) || passedAssessment; // Assessment passes all lessons

                                return (
                                <button
                                    key={lesson.id}
                                    onClick={() => onSelectLesson(lesson)}
                                    className={`
                                    w-full flex items-center justify-between p-3 rounded-lg border text-left transition-all
                                    bg-white hover:bg-white hover:shadow-md border-transparent hover:border-orange-200
                                    ${isCompleted ? 'bg-green-50 border-green-100' : ''}
                                    `}
                                >
                                    <div className="flex items-center gap-3">
                                    {isCompleted ? <Star size={14} className="text-green-500 fill-current" /> : <Unlock size={14} className="text-orange-500" />}
                                    <div>
                                        <span className="font-bold block text-sm text-stone-800">{lesson.root}</span>
                                        <span className="text-xs text-stone-500">{lesson.meaning || "..."}</span>
                                    </div>
                                    </div>
                                    {isCompleted && <span className="text-[10px] font-bold text-green-600 bg-green-100 px-2 py-0.5 rounded-full">DONE</span>}
                                </button>
                                );
                            })}
                            </div>
                        )}
                        </div>
                    );
                    })}
                </div>
                </div>
            );
        })}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AppView, Lesson, User, TierAssessmentResult } from './types';
import { getCurrentUser, logoutUser, saveUserProgress } from './services/authService';
import { Dashboard } from './components/Dashboard';
import { LessonFlow } from './components/LessonFlow';
import { WordGarden } from './components/WordGarden';
import { LoginScreen } from './components/LoginScreen';
import { TierAssessment } from './components/TierAssessment';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<AppView>(AppView.LOGIN);
  const [activeLesson, setActiveLesson] = useState<Lesson | null>(null);
  const [activeAssessment, setActiveAssessment] = useState<{tierId: number, roots: string[]} | null>(null);

  // Check for existing session
  useEffect(() => {
    const sessionUser = getCurrentUser();
    if (sessionUser) {
        setUser(sessionUser);
        setView(AppView.DASHBOARD);
    }
  }, []);

  const handleLogin = (loggedInUser: User) => {
      setUser(loggedInUser);
      setView(AppView.DASHBOARD);
  };

  const handleLogout = () => {
      logoutUser();
      setUser(null);
      setView(AppView.LOGIN);
  };

  const handleLessonSelect = (lesson: Lesson) => {
    setActiveLesson(lesson);
    setView(AppView.LESSON);
  };

  const handleLessonComplete = () => {
    if (!activeLesson || !user) return;

    const newProgress = { ...user.progress };

    // Logic: Only add XP/Tree if lesson wasn't done before
    if (!newProgress.completedLessons.includes(activeLesson.id)) {
        newProgress.completedLessons.push(activeLesson.id);
        newProgress.xp += 100;
        newProgress.garden.trees += 1;

        // Save to DB
        saveUserProgress(user.username, newProgress);
        setUser({ ...user, progress: newProgress });
    }

    // Go to Garden to celebrate
    setTimeout(() => {
        setView(AppView.GARDEN);
    }, 500);
  };

  const handleTakeAssessment = (tierId: number, roots: string[]) => {
      setActiveAssessment({ tierId, roots });
      setView(AppView.ASSESSMENT);
  };

  const handleAssessmentComplete = (result: TierAssessmentResult) => {
      if (!user) return;

      const newProgress = { ...user.progress };

      // Add result history
      newProgress.assessments.push(result);

      if (result.passed) {
          // Unlock next tier if not already unlocked
          const nextTier = result.tierId + 1;
          if (!newProgress.unlockedTiers.includes(nextTier)) {
              newProgress.unlockedTiers.push(nextTier);
          }
          // Also make sure current tier is unlocked (for skipping scenario)
          if (!newProgress.unlockedTiers.includes(result.tierId)) {
              newProgress.unlockedTiers.push(result.tierId);
          }
          newProgress.xp += 500; // Big bonus
      }

      saveUserProgress(user.username, newProgress);
      setUser({ ...user, progress: newProgress });

      // Return to dashboard after short delay or button press (handled in component)
      setTimeout(() => setView(AppView.DASHBOARD), 2000);
  };

  // --- RENDER VIEWS ---

  if (view === AppView.LOGIN || !user) {
      return <LoginScreen onLogin={handleLogin} />;
  }

  if (view === AppView.ASSESSMENT && activeAssessment) {
      return (
          <div className="min-h-screen bg-stone-50 p-6">
            <TierAssessment 
                tierId={activeAssessment.tierId}
                roots={activeAssessment.roots}
                onComplete={handleAssessmentComplete}
                onCancel={() => setView(AppView.DASHBOARD)}
            />
          </div>
      );
  }

  return (
    <div className="antialiased text-stone-900">
      {view === AppView.DASHBOARD && (
        <Dashboard 
          user={user}
          progress={user.progress} 
          onSelectLesson={handleLessonSelect} 
          onGoToGarden={() => setView(AppView.GARDEN)} 
          onTakeAssessment={handleTakeAssessment}
          onLogout={handleLogout}
        />
      )}

      {view === AppView.LESSON && activeLesson && (
        <LessonFlow 
          lesson={activeLesson} 
          onComplete={handleLessonComplete} 
          onExit={() => setView(AppView.DASHBOARD)} 
        />
      )}

      {view === AppView.GARDEN && (
        <WordGarden 
          progress={user.progress} 
          onBack={() => setView(AppView.DASHBOARD)} 
        />
      )}
    </div>
  );
};

export default App;

export enum PartType {
