import { GoogleGenAI, Type } from "@google/genai";
import { DrillQuestion, Lesson, PartType } from '../types';

// Initialize Gemini Client
const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

// Helper to get text safely
const getText = (response: any): string => {
    if (response.text) return response.text;
    if (response.candidates && response.candidates[0] && response.candidates[0].content && response.candidates[0].content.parts && response.candidates[0].content.parts[0].text) {
        return response.candidates[0].content.parts[0].text;
    }
    return '';
};

export const generateDrillQuestions = async (root: string, meaning: string): Promise<DrillQuestion[]> => {
  try {
    const prompt = `
      Create 3 multiple-choice questions to test the understanding of the English root/affix "${root}" which means "${meaning}".
      Focus on derived words.
      The output must be a valid JSON object with a key "questions" containing an array.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            questions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  question: { type: Type.STRING },
                  options: { type: Type.ARRAY, items: { type: Type.STRING } },
                  correctAnswer: { type: Type.STRING },
                  explanation: { type: Type.STRING }
                },
                required: ["question", "options", "correctAnswer", "explanation"]
              }
            }
          }
        }
      }
    });

    const jsonStr = getText(response);
    if (!jsonStr) throw new Error("Empty response from AI");

    const parsed = JSON.parse(jsonStr);
    return parsed.questions || [];

  } catch (error) {
    console.error("Gemini API Error:", error);
    return [
      {
        question: `Which word contains the root ${root}?`,
        options: ["Loading Error", "Please Retry", "Check Connection", "Debug"],
        correctAnswer: "Please Retry",
        explanation: "This is a fallback due to an API error."
      }
    ];
  }
};

export const enrichLessonData = async (root: string, category: string): Promise<Partial<Lesson>> => {
  try {
    const prompt = `
      I need deep educational content for the English morphology lesson on the root/prefix/suffix: "${root}" (Category: ${category}).

      Return a JSON object with:
      1. "meaning": A concise definition.
      2. "phonetic": The IPA pronunciation.
      3. "etymology": Where does it come from? (e.g., Latin 'word' meaning 'x').
      4. "funFact": An interesting linguistic or historical fact about this root.
      5. "metaphor": A visual metaphor.
      6. "parts": Break down a representative word (e.g. IMPORT = IM + PORT).
      7. "richDerivatives": A list of 5 common words with their definition and a usage sentence.

      Schema:
      {
        meaning: string,
        phonetic: string,
        etymology: string,
        funFact: string,
        metaphor: string,
        parts: [{ text: string, type: "PREFIX"|"ROOT"|"SUFFIX", meaning: string }],
        richDerivatives: [{ word: string, definition: string, example: string }]
      }
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            meaning: { type: Type.STRING },
            phonetic: { type: Type.STRING },
            etymology: { type: Type.STRING },
            funFact: { type: Type.STRING },
            metaphor: { type: Type.STRING },
            parts: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  type: { type: Type.STRING, enum: [PartType.PREFIX, PartType.ROOT, PartType.SUFFIX] },
                  meaning: { type: Type.STRING }
                }
              }
            },
            richDerivatives: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  word: { type: Type.STRING },
                  definition: { type: Type.STRING },
                  example: { type: Type.STRING }
                }
              }
            }
          }
        }
      }
    });

    const jsonStr = getText(response);
    if (!jsonStr) throw new Error("Empty response");

    const data = JSON.parse(jsonStr);
    // Backward compatibility for derivatives string array
    data.derivatives = data.richDerivatives?.map((d: any) => d.word) || [];

    return data;

  } catch (error) {
    console.error("Gemini Enrichment Error:", error);
    return {
      meaning: "Meaning unavailable (Offline)",
      phonetic: "/.../",
      etymology: "Origin unknown",
      funFact: "Did you know? This data is currently offline.",
      metaphor: "A blank canvas.",
      derivatives: [],
      richDerivatives: [],
      parts: [{ text: root, type: PartType.ROOT, meaning: "Root" }]
    };
  }
};

export const generateTierAssessment = async (tierId: number, roots: string[]): Promise<DrillQuestion[]> => {
  try {
    const sampledRoots = roots.sort(() => 0.5 - Math.random()).slice(0, 5);

    const prompt = `
      Create a challenge assessment for English Morphology Tier ${tierId}.
      Focus on these roots/affixes: ${sampledRoots.join(', ')}.
      Generate 10 challenging multiple-choice questions.
      JSON output only.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            questions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  question: { type: Type.STRING },
                  options: { type: Type.ARRAY, items: { type: Type.STRING } },
                  correctAnswer: { type: Type.STRING },
                  explanation: { type: Type.STRING }
                },
                required: ["question", "options", "correctAnswer", "explanation"]
              }
            }
          }
        }
      }
    });

    const jsonStr = getText(response);
    const parsed = JSON.parse(jsonStr);
    return parsed.questions || [];

  } catch (error) {
    console.error("Assessment Gen Error", error);
    return [];
  }
};

export const evaluateAssessment = async (tierId: number, score: number, total: number, missedConcepts: string[]): Promise<string> => {
    try {
        const prompt = `
          A student just took the Tier ${tierId} Morphology Exam.
          Score: ${score}/${total}.
          They struggled with questions related to: ${missedConcepts.join(', ') || 'None (Perfect Score)'}.

          Provide a short, encouraging 2-sentence analysis.
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt
        });

        return getText(response);
    } catch (e) {
        return "Assessment complete. Good effort!";
    }
}

import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';

interface WordTreeProps {
  root: string;
  derivatives: string[];
  onNodeClick: (word: string) => void;
  selectedWord: string | null;
}

interface TreeNode {
  name: string;
  children?: TreeNode[];
}

export const WordTree: React.FC<WordTreeProps> = ({ root, derivatives, onNodeClick, selectedWord }) => {
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    if (!svgRef.current) return;

    // Clear previous render
    d3.select(svgRef.current).selectAll("*").remove();

    const width = 600;
    const height = 400;
    const margin = { top: 20, right: 90, bottom: 20, left: 90 };

    const data: TreeNode = {
      name: root,
      children: derivatives.map(d => ({ name: d }))
    };

    const svg = d3.select(svgRef.current)
      .attr("viewBox", `0 0 ${width} ${height}`)
      .append("g")
      .attr("transform", `translate(${margin.left},${margin.top})`);

    const treeLayout = d3.tree<TreeNode>().size([height - margin.top - margin.bottom, width - margin.left - margin.right]);
    const rootNode = d3.hierarchy(data);
    treeLayout(rootNode);

    // Links
    svg.selectAll(".link")
      .data(rootNode.links())
      .enter().append("path")
      .attr("class", "link")
      .attr("fill", "none")
      .attr("stroke", "#a8a29e") // stone-400
      .attr("stroke-width", 2)
      .attr("d", d3.linkHorizontal()
        .x((d: any) => d.y)
        .y((d: any) => d.x) as any
      );

    // Nodes Group
    const nodeGroup = svg.selectAll(".node")
      .data(rootNode.descendants())
      .enter().append("g")
      .attr("class", "node")
      .attr("transform", (d: any) => `translate(${d.y},${d.x})`)
      .style("cursor", "pointer")
      .on("click", (event, d) => {
          onNodeClick(d.data.name);
      });

    // Node Circles
    nodeGroup.append("circle")
      .attr("r", (d) => d.data.name === selectedWord ? 12 : 8)
      .attr("fill", (d) => {
        if (d.data.name === selectedWord) return "#f97316"; // orange-500 selected
        return d.depth === 0 ? "#16a34a" : "#fff"; // Green root, White derived
      }) 
      .attr("stroke", (d) => d.depth === 0 ? "#16a34a" : "#f97316") // Orange border
      .attr("stroke-width", 3)
      .transition() // simple animation
      .duration(500)
      .attr("r", (d) => d.data.name === selectedWord ? 12 : 8);

    // Labels
    nodeGroup.append("text")
      .attr("dy", ".35em")
      .attr("x", (d) => d.children ? -18 : 18)
      .style("text-anchor", (d) => d.children ? "end" : "start")
      .text((d) => d.data.name)
      .style("font-family", "Merriweather, serif")
      .style("font-size", (d) => d.data.name === selectedWord ? "16px" : "14px")
      .style("font-weight", (d) => d.data.name === selectedWord ? "bold" : "normal")
      .style("fill", "#292524"); // stone-800

  }, [root, derivatives, selectedWord]);

  return (
    <div className="w-full flex justify-center bg-white rounded-lg p-4 border border-stone-200 shadow-inner">
      <svg ref={svgRef} className="w-full h-auto max-w-2xl" />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Lesson, DrillQuestion, RichDerivative } from '../types';
import { generateDrillQuestions, enrichLessonData } from '../services/geminiService';
import { DissectionLab } from './DissectionLab';
import { WordTree } from './WordTree';
import { BrainCircuit, Construction, Loader2, RefreshCw, Volume2, History, Lightbulb, BookOpen } from 'lucide-react';

interface LessonFlowProps {
  lesson: Lesson;
  onComplete: () => void;
  onExit: () => void;
}

type Phase = 'PREPARING' | 'DISCOVERY' | 'DISSECTION' | 'DERIVATION' | 'DRILL';

export const LessonFlow: React.FC<LessonFlowProps> = ({ lesson: initialLesson, onComplete, onExit }) => {
  const [lesson, setLesson] = useState<Lesson>(initialLesson);
  const [phase, setPhase] = useState<Phase>('PREPARING');
  const [drillQuestions, setDrillQuestions] = useState<DrillQuestion[]>([]);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [loadingDrill, setLoadingDrill] = useState(false);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [showAnswer, setShowAnswer] = useState(false);

  // State for Derivation Interactivity
  const [selectedDerivative, setSelectedDerivative] = useState<RichDerivative | null>(null);

  // Hydrate lesson data
  useEffect(() => {
    const hydrate = async () => {
        // Hydrate if missing rich data
        if (!lesson.richDerivatives || !lesson.etymology) {
            const enriched = await enrichLessonData(lesson.root, lesson.category);
            setLesson(prev => ({
                ...prev,
                ...enriched
            }));
        }
        setPhase('DISCOVERY');
    };
    hydrate();
  }, [lesson.id]);

  // Load drill questions when entering DRILL phase
  useEffect(() => {
    if (phase === 'DRILL' && drillQuestions.length === 0 && !loadingDrill) {
      setLoadingDrill(true);
      generateDrillQuestions(lesson.root, lesson.meaning || "Unknown").then(questions => {
        setDrillQuestions(questions);
        setLoadingDrill(false);
      }).catch(err => {
         console.error(err);
         setLoadingDrill(false);
      });
    }
  }, [phase, drillQuestions.length, lesson.root, lesson.meaning, loadingDrill]);

  const playAudio = (text: string) => {
    if ('speechSynthesis' in window) {
        const utterance = new SpeechSynthesisUtterance(text);
        utterance.lang = 'en-US';
        utterance.rate = 0.8; 
        window.speechSynthesis.speak(utterance);
    }
  };

  const handleDerivativeClick = (word: string) => {
      const details = lesson.richDerivatives?.find(d => d.word === word);
      if (details) {
          setSelectedDerivative(details);
          playAudio(word);
      } else if (word === lesson.root) {
          setSelectedDerivative({
              word: lesson.root,
              definition: lesson.meaning || "Root meaning",
              example: lesson.etymology || "Origin"
          });
      }
  };

  if (phase === 'PREPARING') {
      return (
          <div className="flex flex-col items-center justify-center min-h-screen bg-stone-50">
              <Loader2 className="animate-spin text-orange-500 mb-4" size={48} />
              <h2 className="text-xl font-serif font-bold text-stone-700">Excavating Root: {lesson.root}</h2>
              <p className="text-stone-500">Unearthing history and usage...</p>
          </div>
      );
  }

  // Phase 1: Deep Discovery
  const renderDiscovery = () => (
    <div className="flex flex-col items-center justify-center space-y-6 animate-fade-in p-4 max-w-2xl mx-auto w-full">

      {/* 1. The Root Card */}
      <div className="bg-white rounded-2xl shadow-xl p-8 border border-stone-100 w-full text-center relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-2 bg-orange-500"></div>
        <h2 className="text-sm font-bold tracking-widest text-stone-400 uppercase mb-2">The Root</h2>
        <div className="flex items-center justify-center gap-3 mb-4">
             <h1 className="text-6xl font-serif font-bold text-stone-900">{lesson.root}</h1>
             <button onClick={() => playAudio(lesson.root)} className="text-orange-500 hover:text-orange-600"><Volume2 size={32} /></button>
        </div>
        <div className="inline-block bg-orange-100 text-orange-800 px-4 py-1 rounded-full text-lg font-medium mb-4">
            {lesson.phonetic}
        </div>
        <p className="text-2xl font-serif text-stone-700">Means: <span className="font-bold">{lesson.meaning}</span></p>
      </div>

      {/* 2. The Origin Story (Etymology) */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 w-full">
          <div className="bg-stone-200 rounded-xl p-6 relative">
             <History className="absolute top-4 right-4 text-stone-400" size={24} />
             <h3 className="font-bold text-stone-700 mb-2">Origin Story</h3>
             <p className="text-stone-600 italic leading-relaxed">{lesson.etymology || "Roots run deep in history..."}</p>
          </div>
          <div className="bg-yellow-50 border border-yellow-200 rounded-xl p-6 relative">
             <Lightbulb className="absolute top-4 right-4 text-yellow-500" size={24} />
             <h3 className="font-bold text-stone-800 mb-2">Fun Fact</h3>
             <p className="text-stone-700 leading-relaxed">{lesson.funFact || "Words connect us across time."}</p>
          </div>
      </div>

      {/* 3. The Visual Metaphor */}
      <div className="w-full bg-stone-900 rounded-xl p-6 flex items-center gap-6 text-white shadow-lg">
          <img 
            src={`https://picsum.photos/100/100?random=${lesson.id}`} 
            className="w-20 h-20 rounded-lg object-cover opacity-80" 
            alt="Metaphor"
          />
          <div>
              <h3 className="font-bold text-orange-400 mb-1">Visual Metaphor</h3>
              <p className="italic text-stone-300">"{lesson.metaphor}"</p>
          </div>
      </div>

      <button 
        onClick={() => setPhase('DISSECTION')}
        className="w-full py-4 bg-orange-600 text-white rounded-xl font-bold hover:bg-orange-700 transition flex items-center justify-center gap-2 shadow-lg mt-4"
      >
        Start Dissection <Construction size={20} />
      </button>
    </div>
  );

  const renderDissection = () => (
    <div className="w-full max-w-4xl mx-auto">
      <h2 className="text-2xl font-serif font-bold text-center mb-6">Phase 2: Dissection</h2>
      <div className="bg-white rounded-2xl shadow-xl p-8 border border-stone-200">
        <div className="text-center mb-8">
            <p className="text-stone-500 uppercase tracking-widest text-sm mb-2">Target Word</p>
            <div className="flex items-center justify-center gap-4">
                <h1 className="text-5xl font-serif font-bold text-stone-900 tracking-wider">
                    {lesson.parts?.map(p => p.text).join('')}
                </h1>
                <button 
                    onClick={() => playAudio(lesson.parts?.map(p => p.text).join('') || '')}
                    className="p-3 rounded-full bg-stone-100 hover:bg-orange-100 text-stone-600 hover:text-orange-600 transition-colors"
                >
                    <Volume2 size={24} />
                </button>
            </div>
        </div>
        {lesson.parts && (
            <DissectionLab 
            parts={lesson.parts} 
            onComplete={() => setPhase('DERIVATION')} 
            />
        )}
      </div>
    </div>
  );

  // Phase 3: Interactive Word Lab
  const renderDerivation = () => (
    <div className="w-full max-w-6xl mx-auto flex flex-col md:flex-row gap-8 items-start">

      {/* Left: Interactive Tree */}
      <div className="flex-1 w-full">
        <h2 className="text-2xl font-serif font-bold mb-4">Phase 3: Word Lab</h2>
        <p className="text-stone-600 mb-4">Click a node to explore how the root meaning changes.</p>

        <WordTree 
            root={lesson.root} 
            derivatives={lesson.derivatives || []} 
            onNodeClick={handleDerivativeClick}
            selectedWord={selectedDerivative?.word || null}
        />

        <div className="mt-8 flex justify-center">
            <button 
                onClick={() => setPhase('DRILL')}
                className="px-8 py-3 bg-stone-900 text-white rounded-full font-bold hover:bg-stone-700 transition flex items-center gap-2"
            >
                Start Drill <BrainCircuit size={20} />
            </button>
        </div>
      </div>

      {/* Right: Detail Card */}
      <div className="w-full md:w-80 flex-shrink-0">
          <div className={`bg-white rounded-2xl shadow-xl p-6 border transition-all duration-300 ${selectedDerivative ? 'border-orange-200 scale-100 opacity-100' : 'border-stone-100 scale-95 opacity-50'}`}>
             {!selectedDerivative ? (
                 <div className="text-center py-12 text-stone-400">
                     <BookOpen size={48} className="mx-auto mb-4 opacity-50" />
                     <p>Select a word from the tree to examine it.</p>
                 </div>
             ) : (
                 <div className="animate-fade-in">
                     <h3 className="text-2xl font-serif font-bold text-stone-800 mb-2">{selectedDerivative.word}</h3>

                     <div className="h-1 w-12 bg-orange-500 mb-4"></div>

                     <h4 className="text-xs font-bold text-stone-400 uppercase tracking-wider mb-1">Definition</h4>
                     <p className="text-stone-800 mb-6 leading-relaxed">{selectedDerivative.definition}</p>

                     <h4 className="text-xs font-bold text-stone-400 uppercase tracking-wider mb-1">Usage</h4>
                     <div className="bg-stone-50 p-4 rounded-lg border-l-4 border-stone-300 italic text-stone-600">
                         "{selectedDerivative.example}"
                     </div>
                 </div>
             )}
          </div>
      </div>
    </div>
  );

  const handleOptionSelect = (option: string) => {
    if (showAnswer) return;
    setSelectedOption(option);
    setShowAnswer(true);
    if (option === drillQuestions[currentQuestionIndex].correctAnswer) {
      setScore(s => s + 10);
    }
  };

  const nextQuestion = () => {
    if (currentQuestionIndex < drillQuestions.length - 1) {
      setCurrentQuestionIndex(prev => prev + 1);
      setSelectedOption(null);
      setShowAnswer(false);
    } else {
      onComplete();
    }
  };

  const renderDrill = () => {
    if (loadingDrill || !drillQuestions || drillQuestions.length === 0) {
      return (
        <div className="flex flex-col items-center justify-center h-64">
           <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-stone-800 mb-4"></div>
           <p className="text-stone-500">AI is crafting your quiz...</p>
           {!loadingDrill && drillQuestions.length === 0 && (
               <div className="mt-4 text-red-500 flex flex-col items-center">
                   <p>Failed to generate questions.</p>
                   <button 
                     onClick={() => {
                         setLoadingDrill(true);
                         generateDrillQuestions(lesson.root, lesson.meaning || "Unknown").then(questions => {
                            setDrillQuestions(questions);
                            setLoadingDrill(false);
                          });
                     }}
                     className="mt-2 text-stone-800 underline flex items-center gap-1"
                   >
                       <RefreshCw size={14}/> Retry
                   </button>
                   <button onClick={onComplete} className="mt-4 text-sm text-stone-500">Skip Drill</button>
               </div>
           )}
        </div>
      );
    }

    const currentQ = drillQuestions[currentQuestionIndex];

    if (!currentQ) return null;

    return (
      <div className="w-full max-w-2xl mx-auto">
        <div className="flex justify-between items-center mb-6">
           <h2 className="text-xl font-serif font-bold">Phase 4: Drill</h2>
           <span className="bg-stone-200 px-3 py-1 rounded-full text-sm font-mono">Q{currentQuestionIndex + 1}/{drillQuestions.length}</span>
        </div>

        <div className="bg-white rounded-2xl shadow-xl p-8 border border-stone-200 relative overflow-hidden">
           <h3 className="text-lg font-medium text-stone-800 mb-6 leading-relaxed">{currentQ.question}</h3>

           <div className="space-y-3">
             {currentQ.options.map((option, idx) => {
               let btnClass = "w-full text-left p-4 rounded-xl border-2 transition-all ";
               if (showAnswer) {
                 if (option === currentQ.correctAnswer) btnClass += "bg-green-100 border-green-500 text-green-800";
                 else if (option === selectedOption) btnClass += "bg-red-50 border-red-300 text-red-800";
                 else btnClass += "border-stone-100 text-stone-400";
               } else {
                 btnClass += "border-stone-100 hover:border-stone-300 hover:bg-stone-50";
               }

               return (
                 <button 
                   key={idx}
                   onClick={() => handleOptionSelect(option)}
                   disabled={showAnswer}
                   className={btnClass}
                 >
                   {option}
                 </button>
               );
             })}
           </div>

           {showAnswer && (
             <div className="mt-6 pt-6 border-t border-stone-100 animate-fade-in">
               <p className="text-sm text-stone-600 mb-4"><span className="font-bold">Explanation:</span> {currentQ.explanation}</p>
               <div className="flex justify-end">
                 <button 
                   onClick={nextQuestion}
                   className="px-6 py-2 bg-stone-900 text-white rounded-lg font-bold hover:bg-stone-700"
                 >
                   {currentQuestionIndex === drillQuestions.length - 1 ? 'Finish Lesson' : 'Next Question'}
                 </button>
               </div>
             </div>
           )}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-stone-50 flex flex-col">
      <div className="bg-white border-b border-stone-200 p-4 flex justify-between items-center sticky top-0 z-10">
        <button onClick={onExit} className="text-stone-500 hover:text-stone-800 text-sm font-bold uppercase tracking-wider">
          &larr; Exit Lesson
        </button>
        <div className="flex gap-2">
           {(['DISCOVERY', 'DISSECTION', 'DERIVATION', 'DRILL'] as Phase[]).map((p, i) => (
             <div key={p} className={`h-2 w-12 rounded-full ${['DISCOVERY', 'DISSECTION', 'DERIVATION', 'DRILL'].indexOf(phase) >= i ? 'bg-orange-500' : 'bg-stone-200'}`} />
           ))}
        </div>
        <div className="font-mono font-bold text-orange-600">XP: {score}</div>
      </div>
      <div className="flex-1 p-6 flex items-center justify-center">
        {phase === 'DISCOVERY' && renderDiscovery()}
        {phase === 'DISSECTION' && renderDissection()}
        {phase === 'DERIVATION' && renderDerivation()}
        {phase === 'DRILL' && renderDrill()}
      </div>
    </div>
  );
};

