        return { analysis: "Review the definitions again.", reviewPoints: ["Check definitions"] };
    }
};

export const generateTierAssessment = async (tierId: number, roots: string[]): Promise<DrillQuestion[]> => {
  try {
    const sampledRoots = roots.sort(() => 0.5 - Math.random()).slice(0, 5);

    const prompt = `
      Create a challenge assessment for English Morphology Tier ${tierId}.
      Focus on these roots/affixes: ${sampledRoots.join(', ')}.
      Generate 10 challenging multiple-choice questions.

      JSON Schema:
      {
        questions: [
          {
            question: string,
            options: string[], // 4 options
            correctAnswer: string,
            explanation: string
          }
        ]
      }
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            questions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  question: { type: Type.STRING },
                  options: { type: Type.ARRAY, items: { type: Type.STRING } },
                  correctAnswer: { type: Type.STRING },
                  explanation: { type: Type.STRING }
                },
                required: ["question", "options", "correctAnswer", "explanation"]
              }
            }
          }
        }
      }
    });

    const jsonStr = getText(response);
    const parsed = JSON.parse(jsonStr);
    return parsed.questions || [];

  } catch (error) {
    console.error("Assessment Gen Error", error);
    return [];
  }
};

export const evaluateAssessment = async (tierId: number, score: number, total: number, missedConcepts: string[]): Promise<string> => {
     try {
        const prompt = `Tier ${tierId} Exam Result: ${score}/${total}. Missed: ${missedConcepts.join(', ')}. Give short feedback.`;
        const response = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: prompt });
        return getText(response);
    } catch (e) { return "Done."; }
};

import React, { useState, useEffect, useCallback } from 'react';
import { DrillQuestion, TierAssessmentResult } from '../types';
import { generateTierAssessment, evaluateAssessment } from '../services/geminiService';
import { CheckCircle, XCircle, Loader2, Award, AlertCircle, RefreshCw } from 'lucide-react';

interface TierAssessmentProps {
  tierId: number;
  roots: string[];
  onComplete: (result: TierAssessmentResult) => void;
  onCancel: () => void;
}

export const TierAssessment: React.FC<TierAssessmentProps> = ({ tierId, roots, onComplete, onCancel }) => {
  const [loading, setLoading] = useState(true);
  const [questions, setQuestions] = useState<DrillQuestion[]>([]);
  const [answers, setAnswers] = useState<Record<number, string>>({});
  const [finished, setFinished] = useState(false);
  const [evaluation, setEvaluation] = useState('');
  const [evaluating, setEvaluating] = useState(false);
  const [error, setError] = useState(false);

  const loadExam = useCallback(() => {
    setLoading(true);
    setError(false);
    generateTierAssessment(tierId, roots)
      .then(qs => {
        if (qs && qs.length > 0) {
            setQuestions(qs);
        } else {
            setError(true);
        }
        setLoading(false);
      })
      .catch(() => {
          setError(true);
          setLoading(false);
      });
  }, [tierId, roots]);

  useEffect(() => {
    loadExam();
  }, [loadExam]);

  const handleSelect = (idx: number, opt: string) => {
    setAnswers(prev => ({ ...prev, [idx]: opt }));
  };

  const submitExam = async () => {
    setFinished(true);
    setEvaluating(true);

    let score = 0;
    const missedConcepts: string[] = [];

    questions.forEach((q, idx) => {
        if (answers[idx] === q.correctAnswer) {
            score++;
        } else {
            missedConcepts.push(q.question.substring(0, 20) + "..."); // Rough tracking
        }
    });

    const finalScore = Math.round((score / questions.length) * 100);
    const passed = finalScore >= 70;

    const feedback = await evaluateAssessment(tierId, score, questions.length, missedConcepts);
    setEvaluation(feedback);
    setEvaluating(false);

    // Auto-save after delay
    setTimeout(() => {
        onComplete({
            tierId,
            score: finalScore,
            passed,
            feedback,
            date: new Date().toISOString()
        });
    }, 4000);
  };

  if (loading) {
      return (
          <div className="flex flex-col items-center justify-center min-h-[60vh]">
              <Loader2 className="animate-spin text-orange-500 mb-4" size={48} />
              <h2 className="text-xl font-bold text-stone-700">Generating Tier {tierId} Exam...</h2>
              <p className="text-stone-500">Consulting the AI for challenging questions.</p>
          </div>
      );
  }

  if (error || questions.length === 0) {
      return (
          <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-8">
              <AlertCircle size={48} className="text-red-500 mb-4" />
              <h2 className="text-2xl font-bold text-stone-800 mb-2">Assessment Generation Failed</h2>
              <p className="text-stone-500 mb-6">The AI historians couldn't assemble your exam papers. Please try again.</p>
              <div className="flex gap-4">
                  <button onClick={onCancel} className="px-6 py-2 rounded-lg text-stone-600 hover:bg-stone-100 font-bold">Cancel</button>
                  <button 
                    onClick={loadExam}
                    className="px-6 py-2 bg-stone-900 text-white rounded-lg hover:bg-stone-700 flex items-center gap-2 font-bold"
                  >
                    <RefreshCw size={18} /> Retry
                  </button>
              </div>
          </div>
      );
  }

  if (finished) {
      const score = Object.keys(answers).filter(k => answers[parseInt(k)] === questions[parseInt(k)].correctAnswer).length;
      const passed = (score / questions.length) >= 0.7;

      return (
          <div className="max-w-2xl mx-auto bg-white p-8 rounded-2xl shadow-xl text-center">
              {passed ? (
                  <div className="flex flex-col items-center text-green-600 mb-6">
                      <Award size={64} className="mb-2" />
                      <h2 className="text-3xl font-serif font-bold">Tier Mastered!</h2>
                  </div>
              ) : (
                  <div className="flex flex-col items-center text-orange-600 mb-6">
                      <AlertCircle size={64} className="mb-2" />
                      <h2 className="text-3xl font-serif font-bold">Keep Practicing</h2>
                  </div>
              )}

              <p className="text-4xl font-bold text-stone-800 mb-6">{score} / {questions.length}</p>

              <div className="bg-stone-50 p-6 rounded-xl border border-stone-200 mb-6">
                 <h3 className="font-bold text-stone-700 mb-2">AI Assessment:</h3>
                 {evaluating ? <Loader2 className="animate-spin mx-auto text-stone-400" /> : <p className="text-stone-600 italic">"{evaluation}"</p>}
              </div>

              <p className="text-stone-400 text-sm">Saving results and returning...</p>
          </div>
      );
  }

  return (
    <div className="max-w-3xl mx-auto pb-12">
        <div className="flex justify-between items-center mb-8">
            <h1 className="text-2xl font-serif font-bold">Tier {tierId} Assessment</h1>
            <button onClick={onCancel} className="text-stone-500 underline">Cancel</button>
        </div>

        <div className="space-y-8">
            {questions.map((q, idx) => (
                <div key={idx} className="bg-white p-6 rounded-xl shadow-sm border border-stone-200">
                    <div className="flex gap-4 mb-4">
                        <span className="bg-stone-900 text-white w-8 h-8 rounded-full flex items-center justify-center font-bold flex-shrink-0">{idx + 1}</span>
                        <h3 className="text-lg font-medium">{q.question}</h3>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-3 pl-12">
                        {q.options.map(opt => (
                            <button
                                key={opt}
                                onClick={() => handleSelect(idx, opt)}
                                className={`p-3 rounded-lg border-2 text-left transition-all ${answers[idx] === opt ? 'border-orange-500 bg-orange-50 text-orange-900' : 'border-stone-100 hover:bg-stone-50'}`}
                            >
                                {opt}
                            </button>
                        ))}
                    </div>
                </div>
            ))}
        </div>

        <div className="mt-8 flex justify-end">
            <button 
                onClick={submitExam}
                disabled={Object.keys(answers).length < questions.length}
                className={`px-8 py-4 rounded-full font-bold text-lg shadow-lg transition-all ${Object.keys(answers).length < questions.length ? 'bg-stone-300 cursor-not-allowed' : 'bg-stone-900 text-white hover:bg-stone-700'}`}
            >
                Submit Exam
            </button>
        </div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { DrillQuestion, Lesson, PartType, RemediationPlan, WordPart } from '../types';

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

const getText = (response: any): string => {
    if (response.text) return response.text;
    if (response.candidates && response.candidates[0] && response.candidates[0].content && response.candidates[0].content.parts && response.candidates[0].content.parts[0].text) {
        return response.candidates[0].content.parts[0].text;
    }
    return '';
};

// 1. Generate Lesson Content (Bilingual, Multi-Dissection)
export const enrichLessonData = async (root: string, category: string): Promise<Partial<Lesson>> => {
  try {
    const prompt = `
      Create a deep, bilingual (English & Vietnamese) morphology lesson for the root/affix: "${root}" (${category}).

      Requirements:
      1. Meaning & Etymology in both languages.
      2. "DissectionPack": Choose 3 distinct words derived from this root (1 easy, 1 medium, 1 hard) to be dissected into parts.
      3. "RichDerivatives": 5 common derived words with definitions and examples in both languages.

      JSON Schema:
      {
        meaning: string,
        meaning_vi: string,
        phonetic: string,
        etymology: string,
        etymology_vi: string,
        funFact: string,
        funFact_vi: string,
        metaphor: string,
        metaphor_vi: string,
        dissectionPack: [
          {
            word: string,
            translation: string,
            parts: [{ text: string, type: "PREFIX"|"ROOT"|"SUFFIX", meaning: string, meaning_vi: string }]
          }
        ],
        richDerivatives: [
            { word: string, definition: string, definition_vi: string, example: string, example_vi: string }
        ]
      }
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: { responseMimeType: "application/json" }
    });

    const jsonStr = getText(response);
    return JSON.parse(jsonStr);

  } catch (error) {
    console.error("Enrichment Error:", error);
    return { meaning: "Error loading content", dissectionPack: [] };
  }
};

// 2. Generate 10 Questions (Pass mark 7/10)
export const generateDrillQuestions = async (root: string, meaning: string): Promise<DrillQuestion[]> => {
  try {
    const prompt = `
      Create 10 multiple-choice questions for the English root "${root}" (${meaning}).
      Questions should test understanding of derived words and context.
      Include Vietnamese explanations.

      JSON Schema:
      {
        questions: [
          {
            question: string,
            options: string[],
            correctAnswer: string,
            explanation: string,
            explanation_vi: string
          }
        ]
      }
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: { responseMimeType: "application/json" }
    });

    const jsonStr = getText(response);
    const parsed = JSON.parse(jsonStr);
    return parsed.questions || [];
  } catch (error) {
    return [];
  }
};

// 3. User Sandbox Verification (Word Lab)
export const verifyUserDerivative = async (root: string, userWord: string): Promise<{
    isValid: boolean;
    analysis: string;
    parts?: WordPart[];
    meaning?: string;
    meaning_vi?: string;
}> => {
    try {
        const prompt = `
          The user suggests the word "${userWord}" contains the root "${root}".
          1. Is this etymologically correct? (isValid: boolean)
          2. If yes, break it down and explain meaning in English and Vietnamese.
          3. If no, explain why briefly.

          JSON Schema:
          {
            isValid: boolean,
            analysis: string, 
            meaning: string,
            meaning_vi: string,
            parts: [{ text: string, type: "PREFIX"|"ROOT"|"SUFFIX", meaning: string }]
          }
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { responseMimeType: "application/json" }
        });

        return JSON.parse(getText(response));
    } catch (e) {
        return { isValid: false, analysis: "AI Analysis Failed." };
    }
};

// 4. Remediation Plan (If failed drill)
export const generateRemediation = async (root: string, missedQuestions: string[]): Promise<RemediationPlan> => {
    try {
        const prompt = `
          A student failed the quiz on root "${root}".
          They missed questions about: ${missedQuestions.join('; ')}.

          Provide a Remediation Plan:
          1. Analysis: Encouraging feedback on what they misunderstood.
          2. ReviewPoints: 3 bullet points (bilingual En/Vi) explaining the concepts they missed.

          JSON Output.
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { responseMimeType: "application/json" }
        });

        return JSON.parse(getText(response));
    } catch (e) {
        return { analysis: "Review the definitions again.", reviewPoints: ["Check definitions"] };
    }
};

export const generateTierAssessment = async (tierId: number, roots: string[]): Promise<DrillQuestion[]> => {
  try {
    const sampledRoots = roots.sort(() => 0.5 - Math.random()).slice(0, 5);

    const prompt = `
      Create a challenge assessment for English Morphology Tier ${tierId}.
      Focus on these roots/affixes: ${sampledRoots.join(', ')}.
      Generate 10 challenging multiple-choice questions.

      JSON Schema:
      {
        questions: [
          {
            question: string,
            options: string[], // 4 options
            correctAnswer: string,
            explanation: string
          }
        ]
      }
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            questions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  question: { type: Type.STRING },
                  options: { type: Type.ARRAY, items: { type: Type.STRING } },
                  correctAnswer: { type: Type.STRING },
                  explanation: { type: Type.STRING }
                },
                required: ["question", "options", "correctAnswer", "explanation"]
              }
            }
          }
        }
      }
    });

    const jsonStr = getText(response);
    const parsed = JSON.parse(jsonStr);
    return parsed.questions || [];

  } catch (error) {
    console.error("Assessment Gen Error", error);
    return [];
  }
};

export const evaluateAssessment = async (tierId: number, score: number, total: number, missedConcepts: string[], timeTakenSeconds: number): Promise<string> => {
     try {
        const prompt = `
          Tier ${tierId} Exam Result:
          Score: ${score}/${total}.
          Time Taken: ${timeTakenSeconds} seconds.
          Missed Concepts: ${missedConcepts.join(', ')}.

          Task: Give concise, constructive feedback.
          CRITICAL:
          1. If Time Taken is under 30 seconds and score is low, scold them for guessing wildly (random picking).
          2. If Time Taken is under 30 seconds and score is high, praise their speed.
          3. Format with bolding (**text**) for emphasis.
        `;
        const response = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: prompt });
        return getText(response);
    } catch (e) { return "Assessment complete."; }
};

import React, { useState, useEffect, useCallback } from 'react';
import { DrillQuestion, TierAssessmentResult } from '../types';
import { generateTierAssessment, evaluateAssessment } from '../services/geminiService';
import { CheckCircle, XCircle, Loader2, Award, AlertCircle, RefreshCw, Clock } from 'lucide-react';

interface TierAssessmentProps {
  tierId: number;
  roots: string[];
  onComplete: (result: TierAssessmentResult) => void;
  onCancel: () => void;
}

export const TierAssessment: React.FC<TierAssessmentProps> = ({ tierId, roots, onComplete, onCancel }) => {
  const [loading, setLoading] = useState(true);
  const [questions, setQuestions] = useState<DrillQuestion[]>([]);
  const [answers, setAnswers] = useState<Record<number, string>>({});
  const [finished, setFinished] = useState(false);
  const [evaluation, setEvaluation] = useState('');
  const [evaluating, setEvaluating] = useState(false);
  const [error, setError] = useState(false);

  // Timer State
  const [seconds, setSeconds] = useState(0);

  const loadExam = useCallback(() => {
    setLoading(true);
    setError(false);
    setSeconds(0);
    generateTierAssessment(tierId, roots)
      .then(qs => {
        if (qs && qs.length > 0) {
            setQuestions(qs);
        } else {
            setError(true);
        }
        setLoading(false);
      })
      .catch(() => {
          setError(true);
          setLoading(false);
      });
  }, [tierId, roots]);

  useEffect(() => {
    loadExam();
  }, [loadExam]);

  // Timer Effect
  useEffect(() => {
    let interval: any;
    if (!loading && !finished && !error) {
        interval = setInterval(() => {
            setSeconds(s => s + 1);
        }, 1000);
    }
    return () => clearInterval(interval);
  }, [loading, finished, error]);

  const formatTime = (secs: number) => {
      const m = Math.floor(secs / 60);
      const s = secs % 60;
      return `${m}:${s < 10 ? '0' : ''}${s}`;
  };

  const formatFeedback = (text: string) => {
      if (!text) return null;
      return text.split('\n').map((line, i) => {
          if (!line.trim()) return <br key={i} />;
          // Parse bold markers **text**
          const parts = line.split(/(\*\*.*?\*\*)/g);
          return (
              <p key={i} className="mb-2 text-stone-700 leading-relaxed">
                  {parts.map((part, j) => {
                      if (part.startsWith('**') && part.endsWith('**')) {
                          return <span key={j} className="font-bold text-stone-900">{part.slice(2, -2)}</span>;
                      }
                      return part;
                  })}
              </p>
          );
      });
  };

  const handleSelect = (idx: number, opt: string) => {
    setAnswers(prev => ({ ...prev, [idx]: opt }));
  };

  const submitExam = async () => {
    setFinished(true);
    setEvaluating(true);

    let score = 0;
    const missedConcepts: string[] = [];

    questions.forEach((q, idx) => {
        if (answers[idx] === q.correctAnswer) {
            score++;
        } else {
            missedConcepts.push(q.question); // Send full question for better context
        }
    });

    const finalScore = Math.round((score / questions.length) * 100);
    const passed = finalScore >= 70;

    const feedback = await evaluateAssessment(tierId, score, questions.length, missedConcepts, seconds);
    setEvaluation(feedback);
    setEvaluating(false);

    // Auto-save after delay
    setTimeout(() => {
        onComplete({
            tierId,
            score: finalScore,
            passed,
            feedback,
            date: new Date().toISOString()
        });
    }, 6000); // Increased delay so user can read feedback
  };

  if (loading) {
      return (
          <div className="flex flex-col items-center justify-center min-h-[60vh]">
              <Loader2 className="animate-spin text-orange-500 mb-4" size={48} />
              <h2 className="text-xl font-bold text-stone-700">Generating Tier {tierId} Exam...</h2>
              <p className="text-stone-500">Consulting the AI for challenging questions.</p>
          </div>
      );
  }

  if (error || questions.length === 0) {
      return (
          <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-8">
              <AlertCircle size={48} className="text-red-500 mb-4" />
              <h2 className="text-2xl font-bold text-stone-800 mb-2">Assessment Generation Failed</h2>
              <p className="text-stone-500 mb-6">The AI historians couldn't assemble your exam papers. Please try again.</p>
              <div className="flex gap-4">
                  <button onClick={onCancel} className="px-6 py-2 rounded-lg text-stone-600 hover:bg-stone-100 font-bold">Cancel</button>
                  <button 
                    onClick={loadExam}
                    className="px-6 py-2 bg-stone-900 text-white rounded-lg hover:bg-stone-700 flex items-center gap-2 font-bold"
                  >
                    <RefreshCw size={18} /> Retry
                  </button>
              </div>
          </div>
      );
  }

  if (finished) {
      const score = Object.keys(answers).filter(k => answers[parseInt(k)] === questions[parseInt(k)].correctAnswer).length;
      const passed = (score / questions.length) >= 0.7;

      return (
          <div className="max-w-2xl mx-auto bg-white p-8 rounded-2xl shadow-xl text-center">
              {passed ? (
                  <div className="flex flex-col items-center text-green-600 mb-6">
                      <Award size={64} className="mb-2" />
                      <h2 className="text-3xl font-serif font-bold">Tier Mastered!</h2>
                  </div>
              ) : (
                  <div className="flex flex-col items-center text-orange-600 mb-6">
                      <AlertCircle size={64} className="mb-2" />
                      <h2 className="text-3xl font-serif font-bold">Keep Practicing</h2>
                  </div>
              )}

              <div className="flex justify-center gap-8 mb-6">
                  <div>
                    <p className="text-sm text-stone-500 uppercase font-bold">Score</p>
                    <p className="text-4xl font-bold text-stone-800">{score} / {questions.length}</p>
                  </div>
                  <div>
                    <p className="text-sm text-stone-500 uppercase font-bold">Time</p>
                    <p className={`text-4xl font-bold ${seconds < 30 ? 'text-red-500' : 'text-stone-800'}`}>{formatTime(seconds)}</p>
                  </div>
              </div>

              <div className="bg-stone-50 p-6 rounded-xl border border-stone-200 mb-6 text-left">
                 <h3 className="font-bold text-stone-700 mb-4 border-b pb-2">AI Performance Analysis:</h3>
                 {evaluating ? (
                     <div className="flex items-center justify-center py-4">
                         <Loader2 className="animate-spin text-stone-400 mr-2" />
                         <span className="text-stone-500">Analyzing your speed and accuracy...</span>
                     </div>
                 ) : (
                     <div className="text-sm">
                         {formatFeedback(evaluation)}
                     </div>
                 )}
              </div>

              <p className="text-stone-400 text-sm">Saving results and returning...</p>
          </div>
      );
  }

  return (
    <div className="max-w-3xl mx-auto pb-12">
        <div className="sticky top-0 z-30 bg-stone-50 pt-4 pb-4 border-b border-stone-200 mb-6 flex justify-between items-center px-2">
            <div>
                <h1 className="text-2xl font-serif font-bold">Tier {tierId} Assessment</h1>
                <p className="text-xs text-stone-500">Answer carefully.</p>
            </div>

            <div className="flex items-center gap-4">
                <div className={`flex items-center gap-2 font-mono text-xl font-bold px-4 py-2 rounded-lg ${seconds > 300 ? 'text-red-600 bg-red-50' : 'text-stone-700 bg-white shadow-sm'}`}>
                    <Clock size={20} />
                    {formatTime(seconds)}
                </div>
                <button onClick={onCancel} className="text-stone-500 underline text-sm">Cancel</button>
            </div>
        </div>

        <div className="space-y-8">
            {questions.map((q, idx) => (
                <div key={idx} className="bg-white p-6 rounded-xl shadow-sm border border-stone-200">
                    <div className="flex gap-4 mb-4">
                        <span className="bg-stone-900 text-white w-8 h-8 rounded-full flex items-center justify-center font-bold flex-shrink-0">{idx + 1}</span>
                        <h3 className="text-lg font-medium">{q.question}</h3>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-3 pl-12">
                        {q.options.map(opt => (
                            <button
                                key={opt}
                                onClick={() => handleSelect(idx, opt)}
                                className={`p-3 rounded-lg border-2 text-left transition-all ${answers[idx] === opt ? 'border-orange-500 bg-orange-50 text-orange-900' : 'border-stone-100 hover:bg-stone-50'}`}
                            >
                                {opt}
                            </button>
                        ))}
                    </div>
                </div>
            ))}
        </div>

        <div className="mt-8 flex justify-end">
            <button 
                onClick={submitExam}
                disabled={Object.keys(answers).length < questions.length}
                className={`px-8 py-4 rounded-full font-bold text-lg shadow-lg transition-all ${Object.keys(answers).length < questions.length ? 'bg-stone-300 cursor-not-allowed' : 'bg-stone-900 text-white hover:bg-stone-700'}`}
            >
                Submit Exam
            </button>
        </div>
    </div>
  );
};
